import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'icon';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  // iOS Button Philosophy: Physical interactions, no sharp edges.
  const baseStyles = "inline-flex items-center justify-center font-medium transition-all duration-200 active:scale-[0.98] disabled:opacity-50 disabled:active:scale-100 select-none";

  const variants = {
    // Primary: Deep Forest Green background, White text
    primary: "bg-[#3A5C34] text-white rounded-full hover:bg-[#2d4a29] shadow-sm",

    // Secondary: Soft Pink background, Deep Burgundy text
    secondary: "bg-[#FCCAE2] text-[#5F2427] rounded-full hover:bg-[#fbbad6]",

    // Ghost: Deep Green text, subtle pink hover
    ghost: "text-[#3A5C34] hover:bg-[#FCCAE2]/20 rounded-lg",

    // Icon: Deep Green text, pink hover
    icon: "text-[#3A5C34] hover:bg-[#FCCAE2]/30 rounded-full p-2"
  };

  const sizes = {
    sm: "px-3 py-1 text-[13px] leading-4",
    md: "px-5 py-2 text-[15px] leading-5",
    lg: "px-6 py-3 text-[17px] leading-6"
  };

  const finalClass = `${baseStyles} ${variants[variant]} ${variant === 'icon' ? '' : sizes[size]} ${className}`;

  return (
    <button className={finalClass} {...props}>
      {children}
    </button>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData, CardType } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string, options?: { toggle?: boolean; keepOthers?: boolean }) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onResize: (id: string, geometry: { width: number; height: number; x?: number; y?: number }) => void;
  zoomScale: number;
  children: React.ReactNode;
  title?: string;
  accentColor?: string;
  icon?: React.ReactNode;
  variant?: 'default' | 'minimal' | 'sticky'; 
  className?: string;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  onResize,
  zoomScale,
  children,
  title,
  icon,
  variant = 'default',
  className = ''
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const hasMovedRef = useRef(false);

  const isFixedLayout = [CardType.GRID_PLANNER, CardType.ANALYTICS, CardType.PERSONA].includes(card.type);

  const handleMouseDown = (e: React.MouseEvent) => {
    // Allow Middle Click to bubble to Canvas for Panning
    if (e.button === 1 || isFullscreen) return;

    // Stop propagation so we don't trigger Canvas Marquee or Deselect
    e.stopPropagation();

    // Selection Logic
    if (e.shiftKey) {
        // Shift + Click: Toggle selection
        onSelect(card.id, { toggle: true });
    } else {
        if (!isSelected) {
            // New selection: Clear others immediately
            onSelect(card.id, { keepOthers: false });
        } else {
            // Already selected: Keep group selected (might be start of a group drag)
            onSelect(card.id, { keepOthers: true }); 
        }
    }

    const target = e.target as HTMLElement;
    const isInteractive = 
      target.tagName === 'INPUT' || 
      target.tagName === 'TEXTAREA' || 
      target.isContentEditable ||
      target.tagName === 'BUTTON' || 
      target.closest('button') ||
      target.closest('.no-drag');

    if (!isInteractive) {
      setIsDragging(true);
      hasMovedRef.current = false;
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    }
  };

  const handleResizeStart = (e: React.MouseEvent, corner: string) => {
    e.stopPropagation();
    e.preventDefault();

    const startX = e.clientX;
    const startY = e.clientY;
    const startBounds = { x: card.x, y: card.y, width: card.width, height: card.height };

    const handleMouseMove = (ev: MouseEvent) => {
        const scale = zoomScale;
        const dx = (ev.clientX - startX) / scale;
        const dy = (ev.clientY - startY) / scale;

        let newBounds = { ...startBounds };

        // Width & Height
        if (corner.includes('e')) newBounds.width = Math.max(100, startBounds.width + dx);
        if (corner.includes('s')) newBounds.height = Math.max(100, startBounds.height + dy);

        // Negative axis resizing (Left/Top) requires moving X/Y
        if (corner.includes('w')) {
            const maxDx = startBounds.width - 100;
            const effectiveDx = Math.min(maxDx, dx);
            newBounds.width = startBounds.width - effectiveDx;
            newBounds.x = startBounds.x + effectiveDx;
        }
        if (corner.includes('n')) {
            const maxDy = startBounds.height - 100;
            const effectiveDy = Math.min(maxDy, dy);
            newBounds.height = startBounds.height - effectiveDy;
            newBounds.y = startBounds.y + effectiveDy;
        }

        onResize(card.id, newBounds);
    };

    const handleMouseUp = () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      if (Math.abs(dx) > 1 || Math.abs(dy) > 1) {
          hasMovedRef.current = true;
      }

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = (e: MouseEvent) => {
      if (isDragging) {
        // If we didn't drag, didn't shift-click, and are already selected...
        // This is a "Click-Through" on a group member. Now we deselect the others.
        if (!hasMovedRef.current && isSelected && !e.shiftKey) {
            onSelect(card.id, { keepOthers: false });
        }
        setIsDragging(false);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale, isSelected, onSelect]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  const getSelectionStyles = () => {
    if (isFullscreen) return 'fixed inset-0 z-[9999] w-full h-full rounded-none bg-white overflow-auto';

    // Variant-based styling
    if (variant === 'minimal') {
      return `absolute select-none ${isSelected ? '' : 'hover:ring-1 hover:ring-[#3A5C34]/30'}`;
    }

    if (variant === 'sticky') {
      return `absolute flex flex-col transition-shadow duration-200 cursor-grab active:cursor-grabbing ${isSelected ? 'shadow-2xl z-50' : 'shadow-md hover:shadow-lg z-10'}`;
    }

    // Default Cards
    // Using the Vibrant Yellow for hover rings to make it feel active and creative
    const colors = {
      [CardType.POST]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.STRATEGY_AI]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.ANALYTICS]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.PERSONA]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.GRID_PLANNER]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.PINTEREST]: { hover: 'hover:ring-[#FFD753]' }
    }[card.type] || { hover: 'hover:ring-gray-300' };

    const base = "flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] cursor-grab active:cursor-grabbing absolute";

    if (isSelected) {
      return `${base} shadow-[0_20px_40px_-12px_rgba(58,92,52,0.2)] z-50 scale-[1.005]`;
    } else {
      return `${base} shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:ring-2 hover:ring-offset-0 ${colors.hover}`;
    }
  };

  const cardContent = (
    <div
      ref={containerRef}
      className={`${getSelectionStyles()} ${className}`}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        height: isFixedLayout ? card.height : 'auto', 
        minHeight: isFixedLayout ? undefined : card.height,
        borderRadius: variant === 'default' ? '24px' : undefined,
      } : {}}
      onMouseDown={handleMouseDown} 
      onClick={(e) => e.stopPropagation()}
    >
      {variant === 'default' && (
        <div className={`flex items-center justify-between px-5 pt-5 pb-2 rounded-t-[24px] select-none shrink-0`}>
          <div className="flex items-center gap-2.5 text-gray-900">
            <span className="text-gray-400">{icon}</span>
            <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
          </div>
          <button 
            onClick={toggleFullscreen} 
            className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-[#FCCAE2] hover:text-[#5F2427] transition-colors"
          >
            {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
          </button>
        </div>
      )}

      <div className={`flex-1 flex flex-col min-h-0 ${isFixedLayout ? 'overflow-hidden rounded-b-[24px]' : (variant === 'default' ? 'px-5 pb-5 overflow-visible' : '')}`}>
        {children}
      </div>

      {isSelected && !isFullscreen && (
         <>
            {/* Bounding Box Border - Using Deep Green for "Selected" state */}
            <div className="absolute inset-0 pointer-events-none border border-[#3A5C34] z-50 rounded-[inherit]" />

            {/* Resize Handles - Using Yellow for interaction points */}
            <div 
               className="absolute -top-1.5 -left-1.5 w-3 h-3 bg-[#FFD753] border border-white z-50 cursor-nw-resize pointer-events-auto shadow-sm"
               onMouseDown={(e) => handleResizeStart(e, 'nw')}
            />
            <div 
               className="absolute -top-1.5 -right-1.5 w-3 h-3 bg-[#FFD753] border border-white z-50 cursor-ne-resize pointer-events-auto shadow-sm"
               onMouseDown={(e) => handleResizeStart(e, 'ne')}
            />
            <div 
               className="absolute -bottom-1.5 -left-1.5 w-3 h-3 bg-[#FFD753] border border-white z-50 cursor-sw-resize pointer-events-auto shadow-sm"
               onMouseDown={(e) => handleResizeStart(e, 'sw')}
            />
            <div 
               className="absolute -bottom-1.5 -right-1.5 w-3 h-3 bg-[#FFD753] border border-white z-50 cursor-se-resize pointer-events-auto shadow-sm"
               onMouseDown={(e) => handleResizeStart(e, 'se')}
            />
         </>
      )}
    </div>
  );

  if (isFullscreen) {
    return createPortal(cardContent, document.body);
  }

  return cardContent;
};

import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { BaseCard } from './BaseCard';
import { CardData, TaskList, TaskItem, MediaItem, Comment } from '../../types';
import { 
  FileImage, Paperclip, MessageSquare, Plus, Trash2, 
  Link as LinkIcon, Image as ImageIcon, X, Send, UserPlus, Pencil, Video, Maximize2, Download,
  HardDrive, Loader2, Check, ExternalLink, AlertCircle, ChevronLeft, ChevronRight, Calendar
} from 'lucide-react';

interface PostCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onResize: (id: string, geometry: { width: number; height: number; x?: number; y?: number }) => void;
  zoomScale: number;
  isLinked?: boolean;
}

// --- Helper Components ---

interface MediaPreviewOverlayProps {
  initialItem: MediaItem;
  items: MediaItem[];
  onClose: () => void;
}

const MediaPreviewOverlay: React.FC<MediaPreviewOverlayProps> = ({ initialItem, items, onClose }) => {
  const [currentItem, setCurrentItem] = useState(initialItem);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowLeft') navigate(-1);
      if (e.key === 'ArrowRight') navigate(1);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentItem, items, onClose]);

  // Scroll active thumbnail into view
  useEffect(() => {
    if (scrollRef.current) {
        const index = items.findIndex(i => i.id === currentItem.id);
        if (index !== -1) {
            const thumbnail = scrollRef.current.children[index] as HTMLElement;
            if (thumbnail) {
                thumbnail.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
            }
        }
    }
  }, [currentItem]);

  const navigate = (direction: number) => {
    const currentIndex = items.findIndex(i => i.id === currentItem.id);
    if (currentIndex === -1) return;

    const newIndex = currentIndex + direction;
    if (newIndex >= 0 && newIndex < items.length) {
      setCurrentItem(items[newIndex]);
    }
  };

  if (!currentItem || currentItem.type === 'empty') return null;

  return createPortal(
    <div 
      className="fixed inset-0 z-[9999] flex items-center justify-center bg-white/95 backdrop-blur-xl animate-in fade-in duration-200"
      onClick={onClose}
    >
        {/* Navigation Arrows */}
        <button 
            onClick={(e) => { e.stopPropagation(); navigate(-1); }}
            className="absolute left-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/10 hover:bg-black/5 text-gray-500 hover:text-black transition-all disabled:opacity-30 z-20"
            disabled={items.indexOf(currentItem) === 0}
        >
            <ChevronLeft size={32} />
        </button>
        <button 
            onClick={(e) => { e.stopPropagation(); navigate(1); }}
            className="absolute right-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/10 hover:bg-black/5 text-gray-500 hover:text-black transition-all disabled:opacity-30 z-20"
            disabled={items.indexOf(currentItem) === items.length - 1}
        >
            <ChevronRight size={32} />
        </button>

      <div 
        className="relative w-full h-full flex flex-col items-center justify-center pb-20"
        onClick={e => e.stopPropagation()}
      >
        <div className="relative rounded-2xl overflow-hidden shadow-2xl ring-1 ring-black/10 bg-white max-h-[70vh] max-w-[85vw] flex items-center justify-center">
          {currentItem.type === 'image' && (
            <img src={currentItem.url} alt="Preview" className="max-w-full max-h-[70vh] object-contain" />
          )}
          {currentItem.type === 'video' && (
            <video src={currentItem.url} controls autoPlay className="max-w-full max-h-[70vh] object-contain" />
          )}
          {currentItem.type === 'link' && (
            <div className="w-[600px] h-[400px] flex flex-col items-center justify-center bg-gray-50 text-gray-500">
              <LinkIcon size={64} className="mb-4 opacity-20" />
              <p className="text-lg font-medium">{currentItem.url}</p>
            </div>
          )}
        </div>

        {/* Bottom Bar: Thumbnails + Actions */}
        <div className="absolute bottom-8 flex items-center gap-3 animate-in slide-in-from-bottom-4 duration-300 max-w-[90vw]">

            {/* 1. Thumbnail Strip */}
            <div 
                className="bg-white/80 backdrop-blur-md p-1.5 rounded-2xl border border-gray-200 shadow-lg overflow-x-auto no-scrollbar flex gap-2 max-w-[60vw]"
                ref={scrollRef}
                onClick={(e) => e.stopPropagation()}
            >
                {items.map((item) => (
                    <button
                        key={item.id}
                        onClick={() => setCurrentItem(item)}
                        className={`
                            relative w-10 h-10 rounded-lg overflow-hidden flex-shrink-0 transition-all
                            ${item.id === currentItem.id ? 'ring-2 ring-black ring-offset-1 opacity-100 scale-100' : 'opacity-50 hover:opacity-100 hover:scale-105'}
                        `}
                    >
                        {item.type === 'image' && <img src={item.url} className="w-full h-full object-cover" />}
                        {item.type === 'video' && (
                            <div className="w-full h-full bg-black flex items-center justify-center">
                                <Video size={14} className="text-white" />
                            </div>
                        )}
                        {item.type === 'link' && (
                            <div className="w-full h-full bg-blue-50 flex items-center justify-center text-[#3A5C34]">
                                <LinkIcon size={14} />
                            </div>
                        )}
                    </button>
                ))}
            </div>

            {/* 2. Download Pill */}
            {currentItem.url && (
             <a 
               href={currentItem.url} 
               download 
               onClick={(e) => e.stopPropagation()}
               className="h-12 px-6 rounded-full bg-black text-white shadow-lg border border-gray-800 font-medium hover:scale-105 active:scale-95 transition-all flex items-center gap-2 whitespace-nowrap"
             >
               <Download size={16} />
               <span className="text-[14px]">Download</span>
             </a>
           )}

            {/* 3. Close Circle */}
           <button 
             onClick={onClose}
             className="w-12 h-12 rounded-full bg-white text-gray-900 shadow-lg border border-gray-200 flex items-center justify-center hover:bg-gray-50 hover:scale-105 active:scale-95 transition-all flex-shrink-0"
           >
             <X size={20} />
           </button>

        </div>
      </div>
    </div>,
    document.body
  );
};

interface AddMediaButtonProps {
  onFilesSelected: (files: File[]) => void;
  onPinDropped: (url: string, link: string) => void;
}

const AddMediaButton: React.FC<AddMediaButtonProps> = ({ onFilesSelected, onPinDropped }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);

    // Check for Pinterest Pin drop first
    const dataStr = e.dataTransfer.getData('application/json');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        if (data.type === 'PINTEREST_PIN') {
          onPinDropped(data.url, data.link);
          return;
        }
      } catch (err) { /* ignore */ }
    }

    // Fallback to file drop
    if (e.dataTransfer.files.length > 0) {
      onFilesSelected(Array.from(e.dataTransfer.files));
    }
  };

  return (
    <div
      onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
      onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDragOver(true); }}
      onDragLeave={(e) => { e.preventDefault(); e.stopPropagation(); setIsDragOver(false); }}
      onDrop={handleDrop}
      className={`
        aspect-square rounded-xl border border-dashed flex flex-col items-center justify-center transition-all duration-200 no-drag relative group cursor-pointer
        ${isDragOver ? 'border-[#3A5C34] bg-[#FCCAE2]/20' : 'bg-white border-gray-300 hover:border-[#3A5C34] hover:bg-[#FCCAE2]/10'}
      `}
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        multiple 
        accept="image/*,video/*"
        onChange={(e) => {
          if (e.target.files && e.target.files.length > 0) {
            onFilesSelected(Array.from(e.target.files));
          }
          e.target.value = '';
        }}
      />

      {/* Circular Button Style */}
      <div className="w-8 h-8 rounded-full bg-white border border-gray-200 shadow-sm flex items-center justify-center text-gray-400 group-hover:text-[#3A5C34] group-hover:scale-110 group-active:scale-95 transition-all">
         <Plus size={14} />
      </div>

      {isDragOver && (
          <div className="absolute bottom-2 text-[#3A5C34] font-bold text-[9px] animate-pulse pointer-events-none">DROP</div>
      )}
    </div>
  );
};

interface MediaCubeProps {
  item: MediaItem;
  index: number;
  listType: 'references' | 'finalAssets';
  onRemove: () => void;
  onUpdate: (i: MediaItem) => void;
  onFilesSelected: (files: File[]) => void;
  onPreview: () => void;
  onDropItem: (dragIndex: number, hoverIndex: number, listType: 'references' | 'finalAssets') => void;
}

const MediaCube: React.FC<MediaCubeProps> = ({ 
  item, 
  index, 
  listType,
  onRemove, 
  onUpdate, 
  onFilesSelected, 
  onPreview,
  onDropItem
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDragStart = (e: React.DragEvent) => {
    e.stopPropagation();
    e.dataTransfer.setData('application/json', JSON.stringify({ index, listType }));
    e.dataTransfer.effectAllowed = 'move';

    // Create a drag image
    const dragGhost = document.createElement('div');
    dragGhost.style.width = '40px';
    dragGhost.style.height = '40px';
    dragGhost.style.backgroundColor = '#3A5C34';
    dragGhost.style.borderRadius = '8px';
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 20, 20);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);

    const dataStr = e.dataTransfer.getData('application/json');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);

        // 1. Handle Pinterest Pin Drop (Replace Content)
        if (data.type === 'PINTEREST_PIN') {
            onUpdate({
                ...item,
                type: 'image',
                url: data.url,
                sourceLink: data.link
            });
            return;
        }

        // 2. Handle Reordering
        if (data.listType === listType) {
          onDropItem(data.index, index, listType);
        }
      } catch (err) {
        // ignore JSON parse error
      }
    } else if (e.dataTransfer.files.length > 0) {
      onFilesSelected(Array.from(e.dataTransfer.files));
    }
  };

  return (
    <div 
      className={`
        aspect-square relative group rounded-xl overflow-hidden transition-all duration-300
        bg-white shadow-sm ring-1 ring-black/5
        ${isDragOver ? 'scale-105 ring-2 ring-[#3A5C34] z-10' : ''}
        no-drag cursor-pointer
      `}
      draggable
      onDragStart={handleDragStart}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={(e) => {
        e.stopPropagation();
        onPreview();
      }}
    >
      {item.type === 'image' && <img src={item.url} alt="asset" className="w-full h-full object-cover select-none pointer-events-none" />}
      {item.type === 'video' && (
        <div className="w-full h-full bg-black flex items-center justify-center relative select-none pointer-events-none">
            <video src={item.url} className="w-full h-full object-cover opacity-80" />
            <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-8 h-8 rounded-full bg-white/30 backdrop-blur-md flex items-center justify-center">
                <Video size={14} className="text-white fill-white" />
                </div>
            </div>
        </div>
      )}
      {item.type === 'link' && <div className="w-full h-full flex items-center justify-center bg-blue-50 text-[#3A5C34]"><LinkIcon size={20}/></div>}

      {/* Hover Actions */}
      <div className={`absolute inset-0 bg-black/0 transition-colors duration-200 ${isHovered ? 'bg-black/10' : ''}`}>
          {isHovered && (
            <div className="absolute top-1.5 right-1.5 flex gap-1 animate-in fade-in duration-200">
                <button 
                onClick={(e) => { e.stopPropagation(); onRemove(); }}
                className="w-6 h-6 flex items-center justify-center bg-white/90 backdrop-blur-md rounded-full text-red-500 hover:scale-110 transition-transform shadow-sm"
                >
                <Trash2 size={10} />
                </button>
            </div>
          )}
          {isHovered && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="w-8 h-8 rounded-full bg-white/30 backdrop-blur-md flex items-center justify-center text-white drop-shadow-md">
                <Maximize2 size={14} />
                </div>
            </div>
          )}
      </div>
    </div>
  );
};

interface TaskListBlockProps {
  list: TaskList;
  onUpdate: (l: TaskList) => void;
  onDelete: () => void;
}

const TaskListBlock: React.FC<TaskListBlockProps> = ({ list, onUpdate, onDelete }) => {
  const [newItemText, setNewItemText] = useState("");

  const theme = {
    blue:   { bg: 'bg-blue-50', border: 'border-blue-100', title: 'text-blue-900', text: 'text-blue-800', placeholder: 'placeholder-blue-300', checkbox: 'border-blue-300', checkboxActive: 'bg-blue-500 border-blue-500', icon: 'text-blue-400' },
    green:  { bg: 'bg-emerald-50', border: 'border-emerald-100', title: 'text-emerald-900', text: 'text-emerald-800', placeholder: 'placeholder-emerald-300', checkbox: 'border-emerald-300', checkboxActive: 'bg-emerald-500 border-emerald-500', icon: 'text-emerald-400' },
    yellow: { bg: 'bg-amber-50', border: 'border-amber-100', title: 'text-amber-900', text: 'text-amber-800', placeholder: 'placeholder-amber-300', checkbox: 'border-amber-300', checkboxActive: 'bg-amber-500 border-amber-500', icon: 'text-amber-400' },
    red:    { bg: 'bg-rose-50', border: 'border-rose-100', title: 'text-rose-900', text: 'text-rose-800', placeholder: 'placeholder-rose-300', checkbox: 'border-rose-300', checkboxActive: 'bg-rose-500 border-rose-500', icon: 'text-rose-400' },
    gray:   { bg: 'bg-gray-50', border: 'border-gray-200', title: 'text-gray-900', text: 'text-gray-800', placeholder: 'placeholder-gray-400', checkbox: 'border-gray-300', checkboxActive: 'bg-gray-500 border-gray-500', icon: 'text-gray-400' }
  }[list.color || 'gray'];

  const addItem = () => {
    if (!newItemText.trim()) return;
    const newItem: TaskItem = { id: Date.now().toString(), text: newItemText, done: false };
    onUpdate({ ...list, items: [...list.items, newItem] });
    setNewItemText("");
  };

  const toggleItem = (itemId: string) => {
    const updatedItems = list.items.map(i => i.id === itemId ? { ...i, done: !i.done } : i);
    onUpdate({ ...list, items: updatedItems });
  };

  const deleteItem = (itemId: string) => {
    onUpdate({ ...list, items: list.items.filter(i => i.id !== itemId) });
  };

  return (
    <div className={`mb-3 p-4 rounded-xl border ${theme.bg} ${theme.border} no-drag cursor-auto transition-all`}>
      <div className="flex items-center justify-between mb-3">
        <input 
          value={list.title}
          onChange={(e) => onUpdate({ ...list, title: e.target.value })}
          className={`bg-transparent text-[12px] font-bold uppercase tracking-wider border-none focus:ring-0 p-0 w-full ${theme.title}`}
          placeholder="List Name"
        />
        <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className={`${theme.icon} hover:text-red-500 transition-colors`}>
          <Trash2 size={14}/>
        </button>
      </div>

      <div className="space-y-1.5">
        {list.items.map(item => (
          <div key={item.id} className="flex items-start gap-3 group">
            <button 
              onClick={(e) => { e.stopPropagation(); toggleItem(item.id); }}
              className={`mt-1 w-4 h-4 rounded-full border flex items-center justify-center transition-all flex-shrink-0 ${item.done ? theme.checkboxActive : `bg-transparent ${theme.checkbox}`}`}
            >
              {item.done && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
            </button>
            <div className="flex-1 min-w-0">
               <input 
                  value={item.text}
                  onChange={(e) => {
                    const updated = list.items.map(i => i.id === item.id ? { ...i, text: e.target.value } : i);
                    onUpdate({ ...list, items: updated });
                  }}
                  className={`bg-transparent text-[14px] leading-relaxed w-full border-none focus:ring-0 p-0 ${item.done ? 'text-gray-400 line-through decoration-gray-300' : theme.text}`}
                />
            </div>
            <button onClick={(e) => { e.stopPropagation(); deleteItem(item.id); }} className={`opacity-0 group-hover:opacity-100 ${theme.icon} hover:text-red-500`}>
               <X size={14} />
            </button>
          </div>
        ))}
        <div className="flex items-center gap-3 mt-2 pl-0.5 opacity-70 hover:opacity-100 transition-opacity">
           <Plus size={16} className={theme.icon}/>
           <input 
             value={newItemText}
             onChange={(e) => setNewItemText(e.target.value)}
             onKeyDown={(e) => { if(e.key === 'Enter') addItem(); }}
             placeholder="Add Item"
             className={`bg-transparent text-[14px] border-none focus:ring-0 p-0 ${theme.text} ${theme.placeholder}`}
           />
        </div>
      </div>
    </div>
  );
};

// --- Drive Sync Button Component ---

interface DriveSyncButtonProps {
  sku: string;
  title: string;
  hasAssets: boolean;
  isSynced: boolean;
  driveUrl?: string;
  onSync: () => Promise<void>;
}

const DriveSyncButton: React.FC<DriveSyncButtonProps> = ({ sku, title, hasAssets, isSynced, driveUrl, onSync }) => {
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [showToast, setShowToast] = useState(false);

  const handleClick = async (e: React.MouseEvent) => {
    e.stopPropagation();

    // Safety check
    if (!hasAssets) {
      setStatus('error');
      setTimeout(() => setStatus('idle'), 2000);
      return;
    }

    if (e.shiftKey && driveUrl) {
      window.open(driveUrl, '_blank');
      return;
    }

    setStatus('loading');
    try {
      await onSync();
      setStatus('success');
      setShowToast(true);
      setTimeout(() => {
        setStatus('idle');
        setShowToast(false);
      }, 2500);
    } catch (err) {
      setStatus('error');
      setTimeout(() => setStatus('idle'), 3000);
    }
  };

  const getIcon = () => {
    switch (status) {
      case 'loading': return <Loader2 size={18} className="animate-spin text-blue-600" />;
      case 'success': return <Check size={18} className="text-green-500" />;
      case 'error': return <AlertCircle size={18} className="text-red-500" />;
      default: return <HardDrive size={18} className={isSynced ? "text-[#3A5C34]" : "text-gray-400 group-hover:text-gray-600"} />;
    }
  };

  return (
    <div className="relative flex items-center">
      {/* Toast Notification */}
      {showToast && (
        <div className="absolute bottom-full mb-3 left-1/2 -translate-x-1/2 whitespace-nowrap bg-gray-900 text-white text-[13px] font-medium px-3 py-1.5 rounded-lg shadow-xl animate-in fade-in slide-in-from-bottom-2">
          Assets Synced to Drive
        </div>
      )}

      {/* Main Button */}
      <button 
        onClick={handleClick}
        disabled={status === 'loading'}
        className={`
          group w-9 h-9 rounded-full flex items-center justify-center transition-all duration-200
          ${isSynced ? 'bg-[#FCCAE2] hover:bg-[#ffb4d6]' : 'bg-[#F2F2F7] hover:bg-gray-200'}
          ${status === 'error' ? 'bg-red-50 ring-2 ring-red-100' : ''}
        `}
        title={hasAssets ? (isSynced ? "Sync updates to Drive (Shift+Click to open)" : "Sync Final Assets to Drive") : "No assets to sync"}
      >
        {getIcon()}
      </button>

      {/* External Link Shortcut (Visible on hover if synced) */}
      {isSynced && status === 'idle' && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            if (driveUrl) window.open(driveUrl, '_blank');
          }}
          className="absolute -right-3 -top-2 w-5 h-5 bg-white rounded-full shadow-md border border-gray-100 flex items-center justify-center text-gray-400 hover:text-[#3A5C34] opacity-0 group-hover:opacity-100 transition-opacity"
        >
          <ExternalLink size={10} />
        </button>
      )}
    </div>
  );
};

