export const PostCard: React.FC<PostCardProps> = (props) => {
  const { card, isLinked, isSelected, onUpdateContent } = props;
  const [sku] = useState(card.content?.sku || `P-${Math.random().toString(36).substr(2, 4).toUpperCase()}`);
  const [viewMode, setViewMode] = useState<'edit' | 'comments'>('edit');
  const [title, setTitle] = useState(card.content?.title || "Untitled Post");
  const [date, setDate] = useState(card.content?.date || "");
  const [caption, setCaption] = useState(card.content?.caption || "");

  // Sync local date when external card data changes (e.g. from grid link)
  useEffect(() => {
    if (card.content?.date) {
        setDate(card.content.date);
    }
  }, [card.content?.date]);

  // Initialize without empty items, just content
  const [references, setReferences] = useState<MediaItem[]>((card.content?.references || []).filter((i: MediaItem) => i.type !== 'empty'));
  const [finalAssets, setFinalAssets] = useState<MediaItem[]>((card.content?.finalAssets || []).filter((i: MediaItem) => i.type !== 'empty'));

  const [taskLists, setTaskLists] = useState<TaskList[]>(card.content?.taskLists || []);
  const [comments, setComments] = useState<Comment[]>(card.content?.comments || []);
  const [newComment, setNewComment] = useState("");

  // Drive State
  const [driveInfo, setDriveInfo] = useState({
    synced: !!card.content?.driveFolderId,
    url: card.content?.driveFolderUrl || 'https://drive.google.com'
  });

  // Debounced Sync Effect to update Parent Component
  useEffect(() => {
    const timer = setTimeout(() => {
      const currentContent = {
        ...card.content,
        sku,
        title,
        date,
        caption,
        references,
        finalAssets,
        taskLists,
        comments,
        driveFolderId: driveInfo.synced ? (card.content?.driveFolderId || 'mock-id') : undefined,
        driveFolderUrl: driveInfo.url
      };

      // Simple deep check to prevent unnecessary updates if data hasn't changed (prevents loops)
      if (JSON.stringify(currentContent) !== JSON.stringify(card.content)) {
          onUpdateContent(card.id, currentContent);
      }
    }, 800);

    return () => clearTimeout(timer);
  }, [sku, title, date, caption, references, finalAssets, taskLists, comments, driveInfo, card.content, card.id, onUpdateContent]);


  const [previewContext, setPreviewContext] = useState<{ item: MediaItem; list: MediaItem[] } | null>(null);

  const addTaskList = () => {
    const colors: TaskList['color'][] = ['blue', 'green', 'yellow', 'red', 'gray'];
    const nextColor = colors[taskLists.length % colors.length];

    const newList: TaskList = { id: Date.now().toString(), title: 'New List', color: nextColor, items: [] };
    setTaskLists([...taskLists, newList]);
  };

  const handlePostComment = () => {
    if (!newComment.trim()) return;
    const c: Comment = { id: Date.now().toString(), user: 'You', avatar: 'ME', text: newComment, timestamp: 'Just now' };
    setComments([...comments, c]);
    setNewComment("");
  };

  const handleMediaUpload = (files: File[], listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    const newItems: MediaItem[] = files.map(file => ({
      id: `media-${Date.now()}-${Math.random()}`,
      type: file.type.startsWith('video') ? 'video' : 'image',
      url: URL.createObjectURL(file)
    }));

    if (newItems.length === 0) return;
    setList([...currentList, ...newItems]);
  };

  const handlePinDropped = (url: string, link: string, listType: 'references' | 'finalAssets') => {
      const currentList = listType === 'references' ? references : finalAssets;
      const setList = listType === 'references' ? setReferences : setFinalAssets;

      const newItem: MediaItem = {
          id: `pin-${Date.now()}`,
          type: 'image',
          url: url,
          sourceLink: link
      };
      setList([...currentList, newItem]);
  };

  const handleReorder = (dragIndex: number, hoverIndex: number, listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    const newList = [...currentList];
    const [removed] = newList.splice(dragIndex, 1);
    newList.splice(hoverIndex, 0, removed);

    setList(newList);
  };

  const handleDriveSync = async () => {
    // Mock Async Operation
    return new Promise<void>((resolve, reject) => {
      setTimeout(() => {
        // Randomly succeed
        if (Math.random() > 0.1) {
          setDriveInfo({
            synced: true,
            url: 'https://drive.google.com/drive/folders/mock-folder-id'
          });
          resolve();
        } else {
          reject(new Error("Network Error"));
        }
      }, 1500);
    });
  };

  // Derived state for collapsed view logic
  const isCollapsed = isLinked && !isSelected;

  // New: Determine which assets to preview in collapsed mode
  // Priority: Final Assets > References > None
  const previewAssets = finalAssets.length > 0 ? finalAssets : references;
  const hasAssets = previewAssets.length > 0;

  return (
    <>
      <BaseCard 
        {...props} 
        title={sku} 
        icon={isLinked ? <LinkIcon size={16} className="text-[#3A5C34]"/> : <FileImage size={16} className="text-gray-400"/>}
      >
        <div className="flex flex-col h-full">

          {/* Collapsed Mode */}
          {isCollapsed ? (
            <div className="space-y-3 pt-1 pointer-events-none select-none animate-in fade-in duration-300">

               {/* Header: Title & Synced Date */}
               <div className="space-y-1">
                 <h3 className="text-[16px] font-bold text-gray-900 leading-tight">{title}</h3>
                 {date && (
                   <div className="flex items-center gap-1.5 text-blue-600">
                      <Calendar size={12} className="text-blue-500" />
                      <span className="text-[12px] font-semibold">{date}</span>
                   </div>
                 )}
               </div>

               {/* Asset Preview (Finals or References) */}
               {hasAssets ? (
                 <div className="grid grid-cols-4 gap-2">
                   {previewAssets.slice(0, 8).map((item) => (
                     <div key={item.id} className="aspect-square rounded-md overflow-hidden bg-gray-100 relative shadow-sm ring-1 ring-black/5">
                        {item.type === 'image' && <img src={item.url} className="w-full h-full object-cover" />}
                        {item.type === 'video' && (
                            <div className="w-full h-full bg-gray-900 flex items-center justify-center">
                                <Video size={12} className="text-white opacity-70" />
                            </div>
                        )}
                        {item.type === 'link' && (
                            <div className="w-full h-full bg-blue-50 flex items-center justify-center text-[#3A5C34]">
                                <LinkIcon size={12} />
                            </div>
                        )}

                        {/* Fallback Indicator: If showing references because finals are missing, give a subtle hint (optional, kept simple for now) */}
                     </div>
                   ))}
                   {previewAssets.length > 8 && (
                     <div className="aspect-square rounded-md bg-gray-50 border border-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-400">
                       +{previewAssets.length - 8}
                     </div>
                   )}
                 </div>
               ) : (
                 <div className="py-2 flex items-center gap-2 opacity-50">
                    <div className="w-8 h-8 rounded-md bg-gray-100 border border-dashed border-gray-300 flex items-center justify-center">
                       <ImageIcon size={14} className="text-gray-400"/>
                    </div>
                    <span className="text-[12px] text-gray-400 italic">No assets yet</span>
                 </div>
               )}

               {/* Caption Preview */}
               {caption && (
                  <p className="text-[13px] text-gray-600 leading-relaxed line-clamp-3 font-medium">
                    {caption}
                  </p>
               )}
            </div>
          ) : (
            // Expanded / Normal Mode
            <>
              {viewMode === 'edit' && (
                <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 ease-out">

                  {/* Title Block */}
                  <div className="space-y-1">
                    <input 
                      className="w-full font-bold text-[28px] leading-tight text-gray-900 bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300 no-drag cursor-text" 
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      placeholder="Post Title"
                      onClick={(e) => e.stopPropagation()} 
                    />

                    <div className="flex items-center gap-2">
                        <input 
                            type="date" 
                            className={`
                                text-[13px] font-medium bg-transparent border-none p-0 focus:ring-0 no-drag cursor-pointer
                                ${isLinked ? 'text-[#3A5C34]' : 'text-gray-500'}
                            `}
                            value={date}
                            onChange={(e) => setDate(e.target.value)}
                            onClick={(e) => e.stopPropagation()}
                        />

                        {isLinked && (
                            <div className="flex items-center gap-1.5 px-2 py-1 bg-[#3A5C34]/10 text-[#3A5C34] rounded-md border border-[#3A5C34]/20 animate-in fade-in zoom-in-95 select-none">
                                <LinkIcon size={10} strokeWidth={2.5} />
                                <span className="text-[10px] font-bold tracking-tight">SYNCED</span>
                            </div>
                        )}
                    </div>
                  </div>

                  {/* References */}
                  <div>
                    <div className="flex items-center justify-between mb-3">
                      <span className="text-[13px] font-semibold text-gray-400">References</span>
                    </div>
                    <div className="grid grid-cols-4 gap-3">
                      {references.map((item, i) => (
                        <MediaCube 
                          key={item.id} 
                          item={item} 
                          index={i} 
                          listType="references"
