            </div>

            {/* Post Selection Overlay */}
            {linkingSlotIndex !== null && (
                <div className="absolute inset-0 bg-white/95 backdrop-blur-sm z-30 animate-in fade-in duration-200 flex flex-col p-4 no-drag cursor-auto">
