export const LinkCard: React.FC<LinkCardProps> = (props) => {
  const { card, onUpdateContent, onResize } = props;
  const content = card.content as LinkCardContent;
  const [hasError, setHasError] = useState(false);

  // Initial Fetch Effect
  useEffect(() => {
    if (content.loading) {
      const loadMetadata = async () => {
        try {
          const meta = await fetchLinkMetadata(content.url);
          onUpdateContent(card.id, { ...content, ...meta, loading: false });
        } catch (e) {
          console.error("Failed to fetch metadata", e);
          setHasError(true);
          onUpdateContent(card.id, { ...content, loading: false, title: content.url });
        }
      };
      loadMetadata();
    }
  }, [content.url, content.loading]);

  const handleDoubleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    window.open(content.url, '_blank', 'noopener,noreferrer');
  };

  const getPlatformIcon = () => {
    switch(content.platform) {
      case 'youtube': return <YouTubeLogo />;
      case 'instagram': return <InstagramLogo />;
      case 'pinterest': return <PinterestLogo />;
      default: return content.favicon ? <img src={content.favicon} className="w-4 h-4 rounded-sm" /> : <LinkIcon size={14} className="text-gray-400" />;
    }
  };

  const getDomainFromUrl = (urlStr: string) => {
    try {
      return new URL(urlStr).hostname.replace('www.', '');
    } catch {
      return urlStr;
    }
  };

  const formatCount = (num: number) => {
      if (num >= 1000) return (num / 1000).toFixed(1) + 'k';
      return num;
  };

  // --- RENDERING STRATEGIES ---

  const renderPinterestCollage = () => {
    const images = content.images || [];
    if (images.length === 0) return null;

    if (images.length < 3) {
        // Single Hero or Double Split
        return (
            <div className="w-full h-full bg-gray-100 flex overflow-hidden">
                {images.map((img, i) => (
                    <img key={i} src={img} className="h-full object-cover flex-1 min-w-0" />
                ))}
            </div>
        );
    }

    // Bento Grid (1 Large, 2 Small)
    return (
        <div className="w-full h-full grid grid-cols-2 grid-rows-2 gap-0.5 bg-white">
            <div className="row-span-2 relative">
                <img src={images[0]} className="w-full h-full object-cover" />
            </div>
            <div className="relative">
                <img src={images[1]} className="w-full h-full object-cover" />
            </div>
            <div className="relative">
                <img src={images[2]} className="w-full h-full object-cover" />
                {images.length > 3 && (
                    <div className="absolute inset-0 bg-black/50 flex items-center justify-center text-white font-bold text-xs">
                        +{images.length - 3}
                    </div>
                )}
            </div>
        </div>
    );
  };

  const renderContent = () => {
    // 1. Pinterest Collage
    if (content.platform === 'pinterest' && content.images && content.images.length > 0) {
        return renderPinterestCollage();
    }

    // 2. Standard Image (YouTube, Instagram, Generic)
    if (content.imageUrl && !hasError) {
        return (
            <>
                <img 
                    src={content.imageUrl} 
                    alt="Preview" 
                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                    onError={() => setHasError(true)}
                />
                {content.platform === 'youtube' && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black/5 group-hover:bg-black/10 transition-colors">
                        <div className="w-12 h-12 rounded-full bg-[#FF0000] text-white flex items-center justify-center shadow-lg transform group-hover:scale-110 transition-transform">
                            <Play fill="currentColor" size={16} className="ml-0.5" />
                        </div>
                    </div>
                )}
            </>
        );
    }

    // 3. Fallback Visuals
    return (
        <div className={`w-full h-full flex flex-col items-center justify-center p-4 text-center
            ${content.platform === 'instagram' ? 'bg-gradient-to-tr from-[#f09433] via-[#dc2743] to-[#bc1888]' : 'bg-gray-100'}
        `}>
            {content.platform === 'instagram' ? (
                <div className="text-white">
                    <ImageIcon size={32} strokeWidth={1.5} />
                    <p className="text-[11px] mt-2 font-medium opacity-90">View on Instagram</p>
                </div>
            ) : content.platform === 'pinterest' ? (
                <div className="text-[#E60023]">
                    <ImageIcon size={32} />
                    <p className="text-[11px] mt-2 font-medium text-gray-500">Board Preview</p>
                </div>
            ) : (
                <div className="text-gray-300">
                    <ImageIcon size={32} />
                </div>
            )}
        </div>
    );
  };

  const getPreviewHeightClass = () => {
     if (content.platform === 'youtube') return 'aspect-video';
     if (content.platform === 'instagram') return 'aspect-square';
     if (content.platform === 'pinterest') return 'aspect-square';
     return content.imageUrl ? 'aspect-video' : 'h-32'; 
  };

  return (
    <BaseCard {...props} variant="minimal">
      <div 
        className="w-full h-full bg-white rounded-[20px] shadow-sm overflow-hidden flex flex-col group border border-gray-200 transition-shadow hover:shadow-md"
        onDoubleClick={handleDoubleClick}
      >
        {/* --- HEADER STRIP --- */}
        <div className="h-10 px-4 flex items-center justify-between border-b border-gray-100 bg-white/50 backdrop-blur-sm z-10 shrink-0">
           <div className="flex items-center gap-2 max-w-[85%]">
             <div className="shrink-0 flex items-center justify-center">
               {getPlatformIcon()}
             </div>
             <span className="text-[12px] font-semibold text-gray-700 truncate">
               {content.siteName || getDomainFromUrl(content.url)}
             </span>
           </div>
           <div className="text-gray-400 group-hover:text-[#3A5C34] transition-colors">
              <ExternalLink size={14} />
           </div>
        </div>

        {/* --- PREVIEW AREA --- */}
        <div className={`relative w-full bg-gray-50 flex items-center justify-center overflow-hidden shrink-0 ${getPreviewHeightClass()}`}>
          {content.loading ? (
             <div className="flex flex-col items-center gap-2">
                <Loader2 className="animate-spin text-gray-300" size={20} />
                <span className="text-[10px] text-gray-400 font-medium">Unfurling...</span>
             </div>
          ) : renderContent()}
        </div>

        {/* --- CONTENT FOOTER --- */}
        <div className="flex-1 p-4 flex flex-col min-h-0 bg-white">

           {/* Instagram-Specific Footer Layout */}
           {content.platform === 'instagram' ? (
             <>
               {/* Line 1: Author */}
               {content.author && (
                   <div className="text-[11px] font-medium text-gray-500 mb-1">
                       Post by {content.author}
                   </div>
               )}

               {/* Line 2: Caption (Truncated) */}
               <div className="text-[13px] text-gray-900 leading-snug line-clamp-2 mb-2" title={content.title}>
                   {content.title}
               </div>

               {/* Line 3: Stats (Conditional) */}
               {(content.likes !== undefined || content.commentsCount !== undefined) && (
                   <div className="mt-auto pt-1 flex items-center gap-3 text-[11px] font-medium text-gray-500">
                       {content.likes !== undefined && (
                          <div className="flex items-center gap-1">
                              <Heart size={12} className="fill-gray-400 text-gray-400"/> 
                              <span>{formatCount(content.likes)}</span>
                          </div>
                       )}
                       {content.commentsCount !== undefined && (
                          <div className="flex items-center gap-1">
                              <MessageCircle size={12} className="text-gray-400"/> 
                              <span>{formatCount(content.commentsCount)}</span>
                          </div>
                       )}
                   </div>
               )}
             </>
           ) : (
             /* Generic / YouTube / Pinterest Footer Layout */
             <>
                <h3 className="text-[14px] font-bold text-gray-900 leading-snug line-clamp-2 mb-1" title={content.title}>
                  {content.loading ? 'Fetching title...' : (content.title || content.url)}
                </h3>

                {content.description && !content.loading && (
                  <p className="text-[12px] text-gray-500 leading-relaxed line-clamp-2">
                      {content.description}
                  </p>
                )}

                {content.platform === 'generic' && !content.loading && (
                  <div className="mt-auto pt-2 text-[11px] text-gray-400 font-medium truncate">
                      {getDomainFromUrl(content.url)}
                  </div>
                )}
             </>
           )}

        </div>
      </div>
    </BaseCard>
  );
};

