import React, { useState, useRef, useEffect } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, AdsTestCardContent, AdRound, AdVariation } from '../../types';
import { 
  Beaker, Plus, Upload, Trophy, X, Download, MoreHorizontal, 
  Play, Eye, MousePointer2 
} from 'lucide-react';
import { soundService } from '../../services/soundService';

interface AdsTestCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onResize: (id: string, geometry: { width: number; height: number; x?: number; y?: number }) => void;
  zoomScale: number;
}

export const AdsTestCard: React.FC<AdsTestCardProps> = (props) => {
  const { card, onUpdateContent } = props;
  const content = card.content as AdsTestCardContent;
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeRoundId, setActiveRoundId] = useState<string | null>(null);

  // Initialize Default Content
  useEffect(() => {
    if (!content.rounds) {
      onUpdateContent(card.id, {
        title: "The Lab: Creative Testing",
        rounds: [
          { id: 'r1', name: "Round 1: Hook Testing", variations: [] },
          { id: 'r2', name: "Round 2: Visual Style", variations: [] }
        ]
      });
    }
  }, []);

  const handleAddRound = () => {
    const newRound: AdRound = {
      id: `round-${Date.now()}`,
      name: `Round ${content.rounds.length + 1}: Concept`,
      variations: []
    };
    onUpdateContent(card.id, { ...content, rounds: [...content.rounds, newRound] });
    soundService.play('drop');
  };

  const handleFilesSelected = (files: FileList | null) => {
    if (!files || !activeRoundId) return;

    const newVariations: AdVariation[] = Array.from(files).map(file => ({
      id: `var-${Date.now()}-${Math.random()}`,
      type: file.type.startsWith('video') ? 'video' : 'image',
      url: URL.createObjectURL(file),
      status: 'active',
      ctr: +(Math.random() * 2 + 0.5).toFixed(2) // Mock data
    }));

    const updatedRounds = content.rounds.map(r => 
      r.id === activeRoundId 
      ? { ...r, variations: [...r.variations, ...newVariations] }
      : r
    );

    onUpdateContent(card.id, { ...content, rounds: updatedRounds });
    setActiveRoundId(null);
    soundService.play('drop');
  };

  const toggleStatus = (roundId: string, varId: string) => {
    const updatedRounds = content.rounds.map(r => {
      if (r.id !== roundId) return r;
      return {
        ...r,
        variations: r.variations.map(v => {
          if (v.id !== varId) return v;
          const nextStatus = v.status === 'active' ? 'winner' : (v.status === 'winner' ? 'loser' : 'active');
          if (nextStatus === 'winner') soundService.play('success');
          return { ...v, status: nextStatus };
        })
      };
    });
    onUpdateContent(card.id, { ...content, rounds: updatedRounds });
  };

  const deleteVariation = (roundId: string, varId: string) => {
    const updatedRounds = content.rounds.map(r => {
        if (r.id !== roundId) return r;
        return { ...r, variations: r.variations.filter(v => v.id !== varId) };
    });
    onUpdateContent(card.id, { ...content, rounds: updatedRounds });
  };

  const triggerUpload = (roundId: string) => {
    setActiveRoundId(roundId);
    fileInputRef.current?.click();
  };

  return (
    <BaseCard 
      {...props} 
      title={content.title || "The Lab"} 
      icon={<Beaker size={16} className="text-[#3A5C34]"/>}
    >
      <div className="flex flex-col h-full bg-[#F9FAFB] p-4 gap-4 overflow-y-auto no-scrollbar">
        <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            multiple 
            accept="image/*,video/*"
            onChange={(e) => handleFilesSelected(e.target.files)}
        />

        {content.rounds?.map((round, rIndex) => (
            <div key={round.id} className="flex flex-col gap-3 animate-in fade-in slide-in-from-bottom-2" style={{ animationDelay: `${rIndex * 100}ms` }}>
                {/* Round Header */}
                <div className="flex items-center justify-between px-1">
                    <input 
                        value={round.name}
                        onChange={(e) => {
                            const newRounds = [...content.rounds];
                            newRounds[rIndex].name = e.target.value;
                            onUpdateContent(card.id, { ...content, rounds: newRounds });
                        }}
                        className="bg-transparent font-bold text-[14px] text-gray-800 border-none focus:ring-0 p-0"
                    />
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => triggerUpload(round.id)}
                            className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-[11px] font-medium text-gray-600 hover:border-[#3A5C34] hover:text-[#3A5C34] transition-all shadow-sm"
                        >
                            <Upload size={12} /> Upload
                        </button>
                    </div>
                </div>

                {/* Variations Horizontal Scroll */}
                <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar min-h-[160px]">
                    {round.variations.map(variation => (
                        <div 
                            key={variation.id} 
                            className={`
                                relative group flex-shrink-0 w-32 aspect-[3/4] bg-white rounded-xl shadow-sm overflow-hidden border-2 transition-all duration-300
                                ${variation.status === 'winner' ? 'border-[#FFD753] ring-4 ring-[#FFD753]/20 scale-105 z-10' : (variation.status === 'loser' ? 'border-transparent opacity-60 grayscale' : 'border-transparent hover:border-gray-200')}
                            `}
                        >
                            {/* Media */}
                            {variation.type === 'image' ? (
                                <img src={variation.url} className="w-full h-full object-cover" />
                            ) : (
                                <div className="w-full h-full bg-black relative">
                                    <video src={variation.url} className="w-full h-full object-cover opacity-80" />
                                    <div className="absolute inset-0 flex items-center justify-center">
                                        <Play size={16} className="text-white fill-white" />
                                    </div>
                                </div>
                            )}

                            {/* Status Badge (Winner) */}
                            {variation.status === 'winner' && (
                                <div className="absolute top-2 right-2 w-6 h-6 bg-[#FFD753] rounded-full flex items-center justify-center text-[#5F2427] shadow-md z-20 animate-in zoom-in spin-in-12">
                                    <Trophy size={12} fill="currentColor" />
                                </div>
                            )}

                            {/* Overlay Controls */}
                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-end p-2 gap-1.5">
                                <div className="flex gap-1.5">
                                    <button 
                                        onClick={() => toggleStatus(round.id, variation.id)}
                                        className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide shadow-sm backdrop-blur-md ${variation.status === 'winner' ? 'bg-white text-gray-900' : 'bg-[#3A5C34] text-white'}`}
                                    >
                                        {variation.status === 'winner' ? 'Unmark' : 'Winner'}
                                    </button>
                                    <button 
                                        onClick={() => deleteVariation(round.id, variation.id)}
                                        className="w-7 h-7 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-lg text-white hover:bg-red-500/80 transition-colors"
                                    >
                                        <X size={12} />
                                    </button>
                                </div>
                                <div className="flex items-center justify-between text-[9px] text-white/80 px-1 font-mono">
                                    <span className="flex items-center gap-1"><MousePointer2 size={8}/> {variation.ctr}%</span>
                                    {variation.status === 'loser' && <span className="text-red-300 font-bold">DROP</span>}
                                </div>
                            </div>
                        </div>
                    ))}

                    {/* Empty State / Drop Zone */}
                    {round.variations.length === 0 && (
                        <div 
                            onClick={() => triggerUpload(round.id)}
                            className="w-32 aspect-[3/4] rounded-xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center gap-2 text-gray-300 hover:border-[#3A5C34] hover:bg-[#3A5C34]/5 hover:text-[#3A5C34] transition-all cursor-pointer"
                        >
                            <Plus size={24} />
                            <span className="text-[10px] font-medium">Add Assets</span>
                        </div>
                    )}
                </div>
            </div>
        ))}

        <button 
            onClick={handleAddRound}
            className="w-full py-3 border-2 border-dashed border-gray-200 rounded-xl text-gray-400 font-medium text-[13px] hover:border-[#3A5C34] hover:text-[#3A5C34] hover:bg-[#3A5C34]/5 transition-all flex items-center justify-center gap-2"
        >
            <Plus size={16} /> Add Testing Round
        </button>

      </div>
    </BaseCard>
  );
};

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent, ToolType, StrokePoint } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';
import { PinterestCard } from './cards/PinterestCard';
import { StrokeCard } from './cards/StrokeCard';
import { TextCard } from './cards/TextCard';
import { StickyCard } from './cards/StickyCard';
import { LinkCard } from './cards/LinkCard';
import { GanttCard } from './cards/GanttCard';
import { AdsTestCard } from './cards/AdsTestCard';
import { isValidUrl } from '../services/linkService';
import { soundService } from '../services/soundService';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
  activeTool: ToolType;
  onToolUsed: () => void;
  scale: number;
  onScaleChange: React.Dispatch<React.SetStateAction<number>>;
  isSpacePressed?: boolean;
}

const GRID_HEADER_HEIGHT = 132; 
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ 
  cards, 
  onCardsChange, 
  activeTool, 
  onToolUsed, 
  scale, 
  onScaleChange,
  isSpacePressed = false
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });

  // Interaction States
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  // Track continuous mouse pos for Smart Paste location
  const [cursorPos, setCursorPos] = useState<Position>({ x: 0, y: 0 });

  // Selection States
  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [selectionBox, setSelectionBox] = useState<{ start: Position, current: Position } | null>(null);

  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);

  // Drawing States
  const [currentStroke, setCurrentStroke] = useState<StrokePoint[]>([]);
  const [isDrawing, setIsDrawing] = useState(false);

  // Lasso State
  const [lassoPath, setLassoPath] = useState<Position[]>([]);

  // Snapping / Grid Logic
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; 
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;
      let rawOpacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 50) {
           rawOpacity = (visualSpacing - 15) / 35;
        } else if (visualSpacing > 100) {
           rawOpacity = 1 - (visualSpacing - 100) / 150;
        } else {
           rawOpacity = 1;
        }
      }
      const finalOpacity = Math.max(0, Math.min(1, rawOpacity)) * 0.3;
      if (finalOpacity > 0.01) {
        layers.push({ spacing: visualSpacing, opacity: finalOpacity, key: `grid-layer-${power}` });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    e.preventDefault();
    if (e.ctrlKey || e.metaKey) {
      // Zoom
      const s = Math.exp(-e.deltaY * 0.005);
      const newScale = Math.min(Math.max(0.05, scale * s), 10);
      onScaleChange(newScale);
    } else {
      // Pan
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, [scale]); 

  // --- Coordinate Utilities ---

  const screenToWorld = (sx: number, sy: number) => {
    return {
        x: (sx - pan.x) / scale,
        y: (sy - pan.y) / scale
    };
  };

  // --- SMART PASTE IMPLEMENTATION ---

  useEffect(() => {
    const handlePaste = async (e: ClipboardEvent) => {
        // 1. Check if paste target is an input field
        const target = e.target as HTMLElement;
        if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

        // 2. Check for URL
        const text = e.clipboardData?.getData('text');
        if (text && isValidUrl(text.trim())) {
            e.preventDefault();

            // 3. Determine Paste Location (Cursor or Center Screen)
            let pasteX, pasteY;
            if (cursorPos.x !== 0 && cursorPos.y !== 0) {
                const worldPos = screenToWorld(cursorPos.x, cursorPos.y);
                pasteX = worldPos.x;
                pasteY = worldPos.y;
            } else {
                // Fallback to center if mouse never moved
                const worldPos = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
                pasteX = worldPos.x;
                pasteY = worldPos.y;
            }

            // 4. Create Optimistic Card
            const newLinkCard: CardData = {
                id: `link-${Date.now()}`,
                type: CardType.LINK,
                x: pasteX - 150, // Center the card (width 300 / 2)
                y: pasteY - 100, // Center (height ~200 / 2)
                width: 300,
                height: 240,
                zIndex: 100,
                content: {
                    url: text.trim(),
                    loading: true // Triggers fetching in component
                }
            };

            onCardsChange([...cards, newLinkCard]);
            setSelectedCardIds([newLinkCard.id]);
            soundService.play('drop'); // Sound Feedback
        }
    };

    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [cards, pan, scale, cursorPos, onCardsChange]); // Dependencies for state/coords

  // --- SELECTION HELPERS ---

  const handleSelectionAction = (id: string, options?: { toggle?: boolean, keepOthers?: boolean }) => {
      if (options?.toggle) {
          if (selectedCardIds.includes(id)) {
              setSelectedCardIds(prev => prev.filter(cId => cId !== id));
          } else {
              setSelectedCardIds(prev => [...prev, id]);
          }
      } else if (options?.keepOthers) {
          if (!selectedCardIds.includes(id)) {
              setSelectedCardIds(prev => [...prev, id]);
          }
      } else {
          // Exclusive Select
          setSelectedCardIds([id]);
      }
  };

  // --- MOUSE HANDLERS ---

  const handleMouseDown = (e: React.MouseEvent) => {
    const worldPos = screenToWorld(e.clientX, e.clientY);

    // 1. Panning Priority (Space, Middle Click, or Pan Tool)
    if (isSpacePressed || activeTool === 'PAN' || e.button === 1) {
        setIsPanning(true);
        setLastMousePos({ x: e.clientX, y: e.clientY });
        return;
    }

    // 2. Tool Logic
    if (activeTool === 'SELECT') {
        if (e.button === 0) { // Left Click
            // Check if clicking background (cards stop propagation)
            if (!e.shiftKey) {
               setSelectedCardIds([]); // Clear selection on background click
            }
            // Start Marquee Selection
            setSelectionBox({ 
                start: { x: e.clientX, y: e.clientY }, 
                current: { x: e.clientX, y: e.clientY } 
            });
        }
    } else if (activeTool === 'TEXT') {
        const newCard: CardData = {
            id: `text-${Date.now()}`,
            type: CardType.TEXT,
            x: worldPos.x,
            y: worldPos.y,
            width: 300,
            height: 50,
            zIndex: 100,
            content: { text: 'Type something...', fontSize: 24, fontFamily: 'Inter', textAlign: 'left', color: '#1C1C1E' }
        };
        onCardsChange([...cards, newCard]);
        setSelectedCardIds([newCard.id]);
        onToolUsed(); 
        soundService.play('drop');
    } else if (activeTool === 'STICKY') {
        const newCard: CardData = {
            id: `sticky-${Date.now()}`,
            type: CardType.STICKY,
            x: worldPos.x - 110, 
            y: worldPos.y - 110,
            width: 220,
            height: 220,
            zIndex: 100,
            content: { text: '', color: '#FFF475', fontSize: 24, shape: 'square' }
        };
        onCardsChange([...cards, newCard]);
        setSelectedCardIds([newCard.id]);
        onToolUsed();
        soundService.play('drop');
    } else if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
        setIsDrawing(true);
        setCurrentStroke([{ x: worldPos.x, y: worldPos.y }]);
    } else if (activeTool === 'ERASER') {
        setIsDrawing(true);
    } else if (activeTool === 'LASSO') {
        setIsDrawing(true);
        setLassoPath([{ x: worldPos.x, y: worldPos.y }]);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    // Track cursor for Smart Paste
    setCursorPos({ x: e.clientX, y: e.clientY });

    const worldPos = screenToWorld(e.clientX, e.clientY);

    // Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // Marquee Selection Update
    if (selectionBox) {
        setSelectionBox(prev => ({ ...prev!, current: { x: e.clientX, y: e.clientY } }));
    }

    // Drawing Update
    if (isDrawing) {
        if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
            setCurrentStroke(prev => [...prev, { x: worldPos.x, y: worldPos.y }]);
        } else if (activeTool === 'LASSO') {
            setLassoPath(prev => [...prev, { x: worldPos.x, y: worldPos.y }]);
        } else if (activeTool === 'ERASER') {
            const ERASER_RADIUS = 20 / scale;
            const remainingCards = cards.filter(c => {
                if (c.type !== CardType.STROKE) return true;
                if (
                    worldPos.x < c.x - ERASER_RADIUS || worldPos.x > c.x + c.width + ERASER_RADIUS ||
                    worldPos.y < c.y - ERASER_RADIUS || worldPos.y > c.y + c.height + ERASER_RADIUS
                ) return true;

                const content = c.content;
                const points = content.points as StrokePoint[];
                return !points.some(p => {
                    const px = c.x + p.x;
                    const py = c.y + p.y;
                    const dist = Math.sqrt(Math.pow(px - worldPos.x, 2) + Math.pow(py - worldPos.y, 2));
                    return dist < ERASER_RADIUS;
                });
            });

            if (remainingCards.length !== cards.length) {
                onCardsChange(remainingCards);
            }
        }
    }
  };

  const handleMouseUp = (e: React.MouseEvent) => {
    // Trigger drop sound if we were dragging a card
    if (draggingCardId) {
      soundService.play('drop');
    }

    // Finalize Marquee Selection
    if (selectionBox) {
        const startWorld = screenToWorld(selectionBox.start.x, selectionBox.start.y);
        const endWorld = screenToWorld(e.clientX, e.clientY);

        const minX = Math.min(startWorld.x, endWorld.x);
        const maxX = Math.max(startWorld.x, endWorld.x);
        const minY = Math.min(startWorld.y, endWorld.y);
        const maxY = Math.max(startWorld.y, endWorld.y);

        if (Math.abs(maxX - minX) > 2 || Math.abs(maxY - minY) > 2) {
             const intersectingIds = cards.filter(c => {
                const cRight = c.x + c.width;
                const cBottom = c.y + c.height;
                return (minX < cRight && maxX > c.x && minY < cBottom && maxY > c.y);
            }).map(c => c.id);

            if (e.shiftKey) {
                const newSet = new Set([...selectedCardIds, ...intersectingIds]);
                setSelectedCardIds(Array.from(newSet));
            } else {
                setSelectedCardIds(intersectingIds);
            }
        }
        setSelectionBox(null);
    }

    if (isDrawing) {
        if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
            if (currentStroke.length > 2) {
                const xs = currentStroke.map(p => p.x);
                const ys = currentStroke.map(p => p.y);
                const minX = Math.min(...xs);
                const minY = Math.min(...ys);
                const maxX = Math.max(...xs);
                const maxY = Math.max(...ys);
                const width = maxX - minX;
                const height = maxY - minY;

                const relativePoints = currentStroke.map(p => ({
                    x: p.x - minX,
                    y: p.y - minY,
                    p: p.p
                }));

                const newCard: CardData = {
                    id: `stroke-${Date.now()}`,
                    type: CardType.STROKE,
                    x: minX,
                    y: minY,
                    width: Math.max(width, 1), 
                    height: Math.max(height, 1),
                    zIndex: 50,
                    content: {
                        points: relativePoints,
                        color: activeTool === 'HIGHLIGHTER' ? '#FFE500' : '#1C1C1E',
                        width: activeTool === 'HIGHLIGHTER' ? 20 : 4,
                        isHighlighter: activeTool === 'HIGHLIGHTER'
                    }
                };
                onCardsChange([...cards, newCard]);
            }
        } else if (activeTool === 'LASSO') {
            if (lassoPath.length > 2) {
                const lx = lassoPath.map(p => p.x);
                const ly = lassoPath.map(p => p.y);
                const minX = Math.min(...lx);
                const minY = Math.min(...ly);
                const maxX = Math.max(...lx);
                const maxY = Math.max(...ly);

                const hit = cards.filter(c => 
                    c.x >= minX && c.x + c.width <= maxX &&
                    c.y >= minY && c.y + c.height <= maxY
                ).map(c => c.id);

                if (hit.length > 0) setSelectedCardIds(hit);
            }
        }
    }

    setIsPanning(false);
    setIsDrawing(false);
    setCurrentStroke([]);
    setLassoPath([]);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    const movedCard = cards.find(c => c.id === id);
    if (!movedCard) return; 

    const dx = x - movedCard.x;
    const dy = y - movedCard.y;

    if (draggingCardId !== id) setDraggingCardId(id);

    if (selectedCardIds.includes(id)) {
        const newCards = cards.map(c => {
            if (selectedCardIds.includes(c.id)) {
                return { ...c, x: c.x + dx, y: c.y + dy };
            }
            return c;
        });
        onCardsChange(newCards);
    } else {
        onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
    }
  };

  const updateCardGeometry = (id: string, geometry: { width?: number, height?: number, x?: number, y?: number }) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, ...geometry } : c));
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    if (selectedCardIds.includes(id)) {
        onCardsChange(cards.filter(c => !selectedCardIds.includes(c.id)));
        setSelectedCardIds([]);
    } else {
        onCardsChange(cards.filter(c => c.id !== id));
        if (selectedCardIds.includes(id)) {
            setSelectedCardIds(prev => prev.filter(cid => cid !== id));
        }
    }
  };

  const bringToFront = (id: string, options?: { toggle?: boolean, keepOthers?: boolean }) => {
    handleSelectionAction(id, options);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  // --- GRID PLANNER LINKING HANDLERS ---

  const handleLinkPost = (gridId: string, slotIndex: number, postId: string) => {
      const newCards = cards.map(c => {
          if (c.id === gridId) {
             const content = c.content as GridPlannerContent;
             const newConnections = { ...content.connections, [slotIndex]: postId };
             return { ...c, content: { ...content, connections: newConnections } };
          }
          return c;
      });
      onCardsChange(newCards);
  };

  const handleUnlink = (gridId: string, slotIndex: number, _postId: string) => {
      const newCards = cards.map(c => {
          if (c.id === gridId) {
             const content = c.content as GridPlannerContent;
             const newConnections = { ...content.connections };
             delete newConnections[slotIndex];
             return { ...c, content: { ...content, connections: newConnections } };
          }
          return c;
      });
      onCardsChange(newCards);
  };

  const handleSwapSlots = (gridId: string, slotA: number, slotB: number) => {
      const newCards = cards.map(c => {
          if (c.id === gridId) {
             const content = c.content as GridPlannerContent;
             const connections = { ...content.connections };

             const postA = connections[slotA];
             const postB = connections[slotB];

             if (postB) connections[slotA] = postB; else delete connections[slotA];
             if (postA) connections[slotB] = postA; else delete connections[slotB];

             return { ...c, content: { ...content, connections } };
          }
          return c;
      });
      onCardsChange(newCards);
  };

  // --- Keyboard Shortcuts ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.key === 'Delete' || e.key === 'Backspace') {
          if (selectedCardIds.length > 0) {
              onCardsChange(cards.filter(c => !selectedCardIds.includes(c.id)));
              setSelectedCardIds([]);
          }
      }
      if (e.key === 'Escape') {
          setSelectedCardIds([]);
          setSelectionBox(null);
          setIsDrawing(false);
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'a') {
          e.preventDefault();
          setSelectedCardIds(cards.map(c => c.id));
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardIds, cards]);

  const isPostLinked = (postId: string) => {
    return cards.some(c => 
      c.type === CardType.GRID_PLANNER && 
      Object.values((c.content as GridPlannerContent).connections || {}).includes(postId)
    );
  };

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardIds.includes(card.id),
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      onUpdateContent: updateCardContent,
      onResize: updateCardGeometry,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} isLinked={isPostLinked(card.id)} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUnlink={handleUnlink} 
            onLinkPost={handleLinkPost} 
            onSwapSlots={handleSwapSlots}
            hoveredSlotIndex={null}
          />
        );
      case CardType.PINTEREST:
        return <PinterestCard {...commonProps} />;
      case CardType.TEXT:
        return <TextCard {...commonProps} />;
      case CardType.STICKY:
        return <StickyCard {...commonProps} />;
      case CardType.STROKE:
        return <StrokeCard {...commonProps} />;
      case CardType.LINK:
        return <LinkCard {...commonProps} />;
      case CardType.GANTT:
        return <GanttCard {...commonProps} />;
      case CardType.ADS_TEST:
        return <AdsTestCard {...commonProps} />;
      default:
        return <PostCard {...commonProps} />;
    }
  };

  const groupBounds = useMemo(() => {
      if (selectedCardIds.length <= 1) return null;
      const selectedCards = cards.filter(c => selectedCardIds.includes(c.id));
      if (selectedCards.length === 0) return null;

      const minX = Math.min(...selectedCards.map(c => c.x));
      const minY = Math.min(...selectedCards.map(c => c.y));
      const maxX = Math.max(...selectedCards.map(c => c.x + c.width));
      const maxY = Math.max(...selectedCards.map(c => c.y + c.height));

      return { x: minX, y: minY, width: maxX - minX, height: maxY - minY };
  }, [selectedCardIds, cards]);

  const isPanMode = isSpacePressed || activeTool === 'PAN' || isPanning;

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full bg-[#f3f4f6] relative overflow-hidden ${isPanMode ? 'cursor-grab active:cursor-grabbing' : (activeTool === 'SELECT' ? 'cursor-default' : 'cursor-crosshair')}`}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none"
          style={{
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 
          }}
        />
      ))}

      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
          pointerEvents: isPanMode ? 'none' : 'auto'
        }}
      >
        {/* Render GANTT cards first (background layer) */}
        {cards.filter(c => c.type === CardType.GANTT).map(renderCard)}
        {/* Render all other cards */}
        {cards.filter(c => c.type !== CardType.GANTT).map(renderCard)}

        {groupBounds && (
            <div 
                className="absolute border border-[#3A5C34] pointer-events-none z-[60]"
                style={{
                    left: groupBounds.x,
                    top: groupBounds.y,
                    width: groupBounds.width,
                    height: groupBounds.height,
                }}
            />
        )}
      </div>

      <div className="absolute inset-0 pointer-events-none">
          <svg className="w-full h-full overflow-visible">
              {isDrawing && currentStroke.length > 0 && (
                  <path 
                    d={`M ${currentStroke.map(p => `${(p.x * scale) + pan.x} ${(p.y * scale) + pan.y}`).join(' L ')}`}
                    stroke={activeTool === 'HIGHLIGHTER' ? '#FFE500' : '#1C1C1E'}
                    strokeWidth={(activeTool === 'HIGHLIGHTER' ? 20 : 4) * scale}
                    fill="none"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeOpacity={activeTool === 'HIGHLIGHTER' ? 0.5 : 1}
                  />
              )}
              {isDrawing && activeTool === 'LASSO' && lassoPath.length > 0 && (
                   <path 
                   d={`M ${lassoPath.map(p => `${(p.x * scale) + pan.x} ${(p.y * scale) + pan.y}`).join(' L ')} Z`}
                   stroke="#3A5C34"
                   strokeWidth={2}
                   fill="rgba(58, 92, 52, 0.1)"
                   strokeDasharray="5,5"
                 />
              )}
          </svg>

          {selectionBox && (
              <div 
                  className="absolute bg-[#3A5C34]/10 border border-[#3A5C34] z-[9999]"
                  style={{
                      left: Math.min(selectionBox.start.x, selectionBox.current.x),
                      top: Math.min(selectionBox.start.y, selectionBox.current.y),
                      width: Math.abs(selectionBox.current.x - selectionBox.start.x),
                      height: Math.abs(selectionBox.current.y - selectionBox.start.y),
                  }}
              />
          )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveWorkspacesToFirestore, loadWorkspacesFromFirestore } from './services/firebase';
import { soundService } from './services/soundService';
import { 
  Plus, 
  FileImage, 
  Search,
  ChevronDown,
  Check,
  LayoutGrid,
  Trash2,
  Loader2,
  Type,
  StickyNote,
  PenTool,
  Undo2,
  Redo2,
  Menu,
  ChevronLeft,
  X,
  Sparkles,
  TrendingUp,
  Image as ImageIcon,
  Home,
  CalendarRange,
  Beaker
} from 'lucide-react';

// --- INITIAL DATA & TEMPLATES ---

const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const INITIAL_NODES: Record<string, FileSystemNode> = {
  'root-campaigns': { id: 'root-campaigns', type: 'folder', name: 'Campaigns', parentId: null, isExpanded: true },
  'root-channels': { id: 'root-channels', type: 'folder', name: 'Channels', parentId: null, isExpanded: false },
  'root-brand': { id: 'root-brand', type: 'folder', name: 'Brand System', parentId: null },

  // Channels children
  'folder-ig': { id: 'folder-ig', type: 'folder', name: 'Instagram', parentId: 'root-channels' },
  'page-mar-26': { id: 'page-mar-26', type: 'page', name: 'March 2026 Content', parentId: 'folder-ig' },

  // Whiteboard inside page
  'wb-mar-plan': { 
    id: 'wb-mar-plan', 
    type: 'whiteboard', 
    name: 'March Content Plan', 
    parentId: 'page-mar-26', 
    whiteboardData: DEFAULT_WHITEBOARD_DATA,
    lastEdited: '2h ago',
    isFavorite: true
  }
};

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

export default function App() {
  // --- Navigation State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>(INITIAL_NODES);
  const [activeNodeId, setActiveNodeId] = useState<string>('root'); // Start on Home (root)

  // --- Whiteboard State (Active Board) ---
  // When a whiteboard is active, these represent its internal tabs/workspaces
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');

  // --- Canvas Tools & State ---
  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  // --- UI State ---
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false); // Tool drawer
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Undo/Redo Stacks (Per Whiteboard Session)
  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- DERIVED STATE ---
  // Determine if we are in a special view or a real node
  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  // Resolve what to show in PageView
  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    // Root shows top-level items (parentId === null)
    displayedChildren = Object.values(nodes).filter(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null, icon: '🕒' };
    // Recents shows all items, ideally sorted by date (mock: show all whiteboards/pages)
    displayedChildren = Object.values(nodes).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null, icon: '⭐️' };
    // Favorites shows items with isFavorite === true
    displayedChildren = Object.values(nodes).filter(n => n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = Object.values(nodes).filter(n => n.parentId === activeNodeId);
  } else {
    // Fallback
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  // --- NAVIGATION HANDLERS ---

  const handleNavigate = (id: string) => {
    // If leaving a whiteboard, save its state back to the node tree
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: {
                ...prev[activeNodeId],
                whiteboardData: workspaces
            }
        }));
    }

    const targetNode = nodes[id];
    // If target is a whiteboard, load its data
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }

    setActiveNodeId(id);
    // Reset Canvas State
    setScale(1);
    setHistory([]);
    setFuture([]);
  };

  const handleToggleExpand = (id: string) => {
    setNodes(prev => ({
        ...prev,
        [id]: { ...prev[id], isExpanded: !prev[id].isExpanded }
    }));
  };

  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    soundService.play('success'); // Sound Feedback

    const newId = `${type}-${Date.now()}`;
    // If we are in a special view (like Home/Recents), default parent to null (Root) unless we are inside a folder
    const effectiveParentId = (isSpecialView || !nodes[activeNodeId]) ? null : activeNodeId;

    const newNode: FileSystemNode = {
        id: newId,
        type,
        name: `New ${type.charAt(0).toUpperCase() + type.slice(1)}`,
        parentId: parentId || effectiveParentId,
        isExpanded: true,
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined,
        lastEdited: 'Just now'
    };

    setNodes(prev => {
        // If parent exists and wasn't expanded, expand it
        const parentUpdates = (parentId && prev[parentId]) ? { [parentId]: { ...prev[parentId], isExpanded: true } } : {};
        return { ...prev, ...parentUpdates, [newId]: newNode };
    });

    if (type !== 'folder') {
        handleNavigate(newId);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
    setNodes(prev => ({
        ...prev,
        [id]: { ...prev[id], ...updates }
    }));
  };

  const handleToggleFavorite = (id: string) => {
    soundService.play('toggle'); // Sound Feedback
    setNodes(prev => ({
      ...prev,
      [id]: { ...prev[id], isFavorite: !prev[id].isFavorite }
    }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const newNodes = { ...prev };
          // Recursively delete children
          const deleteRecursively = (nodeId: string) => {
              Object.values(newNodes).filter(n => n.parentId === nodeId).forEach(child => deleteRecursively(child.id));
              delete newNodes[nodeId];
          };
          deleteRecursively(id);
          return newNodes;
      });

      // If we deleted the active node, go to root
      if (activeNodeId === id || !nodes[activeNodeId]) {
          handleNavigate('root');
      }
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
     setNodes(prev => ({
         ...prev,
         [dragId]: { ...prev[dragId], parentId: targetId }
     }));
  };

  const handleExitWhiteboard = () => {
    // Navigate to parent if exists, otherwise fallback to root folder
    if (realNode && realNode.parentId && nodes[realNode.parentId]) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  // --- WHITEBOARD ACTIONS ---

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);

    const updatedWorkspaces = workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    );
    setWorkspaces(updatedWorkspaces);

    // Auto-save to node state (throttled in real app, immediate here for sync)
    setNodes(prev => ({
        ...prev,
        [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces }
    }));
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(prev => prev.slice(0, -1));

    updateCardsNoHistory(previous);
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(prev => prev.slice(1));

    updateCardsNoHistory(next);
  };

  const updateCardsNoHistory = (newCards: CardData[]) => {
      const updated = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  // --- GLOBAL KEYBOARD LISTENERS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);

      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
          if (e.key.toLowerCase() === 't') setActiveTool('TEXT');
          if (e.key.toLowerCase() === 'n') setActiveTool('STICKY');
          if (e.key.toLowerCase() === 'p') setActiveTool('PEN');
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') { e.preventDefault(); handleUndo(); }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') { e.preventDefault(); handleRedo(); }
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, history, future, activeWorkspaceId, isWhiteboardMode]);

  // --- INTERNAL TAB MANAGEMENT (Like Old App.tsx) ---
  const addCard = (type: CardType) => {
    soundService.play('drop'); // Sound Feedback

    let width = 360;
    let height = 200;

    // Custom dimensions for specific types
    if (type === CardType.GRID_PLANNER) { width = 320; height = 500; }
    if (type === CardType.GANTT) { width = 800; height = 400; }
    if (type === CardType.ADS_TEST) { width = 600; height = 500; }

    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - (width / 2),
      y: window.innerHeight / 2 - (height / 2),
      width,
      height, 
      zIndex: type === CardType.GANTT ? 1 : 100, // Gantt spawns as background
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false); // Close drawer after adding
  };

  const addTab = () => {
    soundService.play('drop'); // Sound Feedback
    const newWs: Workspace = {
      id: `tab-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };


  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* --- SIDEBAR --- */}
      {/* Hidden in Whiteboard Mode */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          onNavigate={handleNavigate}
          onToggleExpand={handleToggleExpand}
          onCreateNode={handleCreateNode}
          onToggleFavorite={handleToggleFavorite}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* --- MAIN CONTENT AREA --- */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">

         {/* Toggle Sidebar Button (Float) - Only show in Page View */}
         {!isSidebarOpen && !isWhiteboardMode && (
             <button 
                onClick={() => setIsSidebarOpen(true)}
                className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"
             >
                 <Menu size={16} />
             </button>
         )}

         {/* --- VIEW: WHITEBOARD --- */}
         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#f3f4f6]">

                {/* Canvas */}
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    isSpacePressed={isSpacePressed}
                />

                {/* --- LEFT HOVER TRIGGER ZONE --- */}
                {/* Invisible strip on left edge to auto-open menu */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* --- MENU DRAWER --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[300px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">

                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input 
                                    type="text" 
                                    placeholder="Search tools..." 
                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-9 pr-4 py-2 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 focus:border-[#3A5C34] transition-all outline-none" 
                                    value={searchTerm} 
                                    onChange={(e) => setSearchTerm(e.target.value)} 
                                />
                            </div>
                        </div>

                        {/* Drawer Content */}
                        <div className="flex-1 overflow-y-auto p-5 no-scrollbar space-y-8">

                            {/* Section 1: Essentials (Grid) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Essentials</h3>
                                <div className="grid grid-cols-4 gap-2">
                                    <button onClick={() => addCard(CardType.POST)} className="aspect-square rounded-xl bg-[#FCCAE2] hover:bg-[#ffb4d6] text-[#5F2427] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <FileImage size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Post</span>
                                    </button>
                                    <button onClick={() => { setActiveTool('TEXT'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-gray-50 hover:bg-gray-100 text-gray-600 flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <Type size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Text</span>
                                    </button>
                                    <button onClick={() => { setActiveTool('STICKY'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#FFD753] hover:bg-[#ffe38a] text-[#5F2427] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <StickyNote size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Note</span>
                                    </button>
                                    <button onClick={() => { setActiveTool('PEN'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-pink-50 hover:bg-pink-100 text-pink-600 flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <PenTool size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Draw</span>
                                    </button>
                                </div>
                            </div>

                            {/* Section 2: Tools & Widgets (List) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Tools & Widgets</h3>
                                <div className="space-y-2">
                                    {/* The Chronos (Gantt) */}
                                    <button onClick={() => addCard(CardType.GANTT)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#3A5C34]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/10 text-[#3A5C34] flex items-center justify-center group-hover:bg-[#3A5C34]/20 transition-colors">
                                            <CalendarRange size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">The Chronos</div>
                                            <div className="text-[11px] text-gray-400">Timeline & Gantt View</div>
                                        </div>
                                    </button>

                                    {/* The Lab (Ads Test) */}
                                    <button onClick={() => addCard(CardType.ADS_TEST)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#5F2427]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427]/10 text-[#5F2427] flex items-center justify-center group-hover:bg-[#5F2427]/20 transition-colors">
                                            <Beaker size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">The Lab</div>
                                            <div className="text-[11px] text-gray-400">Creative Testing Suite</div>
                                        </div>
                                    </button>

                                    {/* Feed Planner: Blue -> Green */}
                                    <button onClick={() => addCard(CardType.GRID_PLANNER)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#FCCAE2]/20 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/10 text-[#3A5C34] flex items-center justify-center group-hover:bg-[#3A5C34]/20 transition-colors">
                                            <LayoutGrid size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">Feed Planner</div>
                                            <div className="text-[11px] text-gray-400">Visually plan Instagram grid</div>
                                        </div>
                                    </button>

                                    {/* Oracle AI: Indigo -> Burgundy */}
                                    <button onClick={() => addCard(CardType.STRATEGY_AI)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#5F2427]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427]/10 text-[#5F2427] flex items-center justify-center group-hover:bg-[#5F2427]/20 transition-colors">
                                            <Sparkles size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">Oracle AI</div>
                                            <div className="text-[11px] text-gray-400">Generate creative strategies</div>
                                        </div>
                                    </button>

                                    {/* Performance: Emerald -> Forest Green */}
                                    <button onClick={() => addCard(CardType.ANALYTICS)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#3A5C34]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/10 text-[#3A5C34] flex items-center justify-center group-hover:bg-[#3A5C34]/20 transition-colors">
                                            <TrendingUp size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">Performance</div>
                                            <div className="text-[11px] text-gray-400">Track campaign KPIs</div>
                                        </div>
                                    </button>

                                    {/* Pinterest: Red -> Burgundy */}
                                    <button onClick={() => addCard(CardType.PINTEREST)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#FCCAE2]/20 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427]/10 text-[#5F2427] flex items-center justify-center group-hover:bg-[#5F2427]/20 transition-colors">
                                            <ImageIcon size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">Pinterest</div>
                                            <div className="text-[11px] text-gray-400">Import boards & pins</div>
                                        </div>
                                    </button>
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Internal Tabs (Workspaces) - Bottom Left */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-2 pl-2 pr-4 pointer-events-auto max-w-full">
                    {workspaces.map(ws => {
                        const isActive = activeWorkspaceId === ws.id;
                        return (
                        <div key={ws.id} className="relative group flex-shrink-0">
                            <button onClick={() => setActiveWorkspaceId(ws.id)} className={`relative h-11 px-4 min-w-[100px] max-w-[180px] flex items-center gap-2.5 rounded-full transition-all duration-300 select-none bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] ${isActive ? 'text-[#3A5C34] font-bold scale-100 z-10 ring-1 ring-[#3A5C34]/30' : 'text-gray-500 hover:text-[#5F2427] hover:scale-[1.02] active:scale-[0.98] z-0 opacity-70 hover:opacity-100'}`}>
                            <div className={`w-2 h-2 rounded-full shadow-sm transition-transform duration-300 border border-white/50 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`} style={{ backgroundColor: ws.color || '#3A5C34' }} />
                            <span className="truncate text-[13px] tracking-tight">{ws.name}</span>
                            {isActive && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="ml-auto p-1 -mr-1 rounded-full hover:bg-black/5 text-[#3A5C34] cursor-pointer transition-colors"><ChevronDown size={12} strokeWidth={2.5} /></div>}
                            </button>
                        </div>
                        );
                    })}
                    <button onClick={addTab} className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"><Plus size={20} strokeWidth={2.5} /></button>
                    </div>
                </div>

                 {/* Top Right Control Cluster: Breadcrumbs + Scale/Undo + Exit */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">

                    {/* 1. Breadcrumb Pill */}
                    <div className="hidden md:flex h-11 px-5 items-center gap-2 rounded-full bg-white/80 backdrop-blur-xl border border-white/60 shadow-sm select-none">
                        <span className="text-[13px] font-medium text-gray-500 max-w-[120px] truncate">{realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}</span>
                        <span className="text-gray-300">/</span>
                        <span className="text-[13px] font-bold text-[#3A5C34] max-w-[160px] truncate">{displayedNode.name}</span>
                    </div>

                    {/* 2. Scale & Undo/Redo */}
                    <div className="h-11 px-2 flex items-center gap-1 rounded-full bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)]">
                        <div className="px-3 text-[13px] font-bold text-gray-600 select-none w-[60px] text-center tracking-tight">{Math.round(scale * 100)}%</div>
                        <div className="w-px h-4 bg-gray-400/30"></div>
                        <button onClick={handleUndo} disabled={history.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Undo2 size={16} strokeWidth={2.5} /></button>
                        <button onClick={handleRedo} disabled={future.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Redo2 size={16} strokeWidth={2.5} /></button>
                    </div>

                    {/* 3. Exit Button */}
                    <button 
                        onClick={handleExitWhiteboard}
                        className="h-11 w-11 rounded-full bg-white/90 backdrop-blur-xl border border-white/60 shadow-sm flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:bg-gray-100 transition-all active:scale-95"
                        title="Exit Whiteboard"
                    >
                        <Home size={20} />
                    </button>
                </div>

                {/* Tools Drawer Button (Visual indicator for the hover zone) */}
                <div className="absolute top-6 left-6 z-40">
                    <button onClick={() => setIsDrawerOpen(true)} className="w-12 h-12 rounded-full bg-[#3A5C34] shadow-lg border border-white/20 flex items-center justify-center text-white hover:scale-110 transition-all">
                       <Plus size={24} strokeWidth={1.5} />
                    </button>
                </div>

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}

                {/* Tab Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <input type="text" className="w-full bg-white/50 border border-black/5 rounded-lg px-2.5 py-1.5 text-[13px] font-medium text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#3A5C34]/20 transition-all" placeholder="Tab Name" value={workspaces.find(w => w.id === colorPickerState?.id)?.name || ''} onChange={(e) => updateTabName(colorPickerState!.id, e.target.value)} autoFocus />
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}
            </div>
         ) : (
            /* --- VIEW: PAGE / FOLDER DASHBOARD --- */
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={handleToggleFavorite}
            />
         )}
      </div>

    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveWorkspacesToFirestore, loadWorkspacesFromFirestore } from './services/firebase';
import { soundService } from './services/soundService';
import { 
  Plus, 
  FileImage, 
  Search,
  ChevronDown,
  Check,
  LayoutGrid,
  Trash2,
  Loader2,
  Type,
  StickyNote,
  PenTool,
  Undo2,
  Redo2,
  Menu,
  ChevronLeft,
  X,
  Sparkles,
  TrendingUp,
  Image as ImageIcon,
  Home,
  CalendarRange,
  Beaker
} from 'lucide-react';

// --- INITIAL DATA & TEMPLATES ---

const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const INITIAL_NODES: Record<string, FileSystemNode> = {
  'root-campaigns': { id: 'root-campaigns', type: 'folder', name: 'Campaigns', parentId: null, isExpanded: true },
  'root-channels': { id: 'root-channels', type: 'folder', name: 'Channels', parentId: null, isExpanded: false },
  'root-brand': { id: 'root-brand', type: 'folder', name: 'Brand System', parentId: null },

  // Channels children
  'folder-ig': { id: 'folder-ig', type: 'folder', name: 'Instagram', parentId: 'root-channels' },
  'page-mar-26': { id: 'page-mar-26', type: 'page', name: 'March 2026 Content', parentId: 'folder-ig' },

  // Whiteboard inside page
  'wb-mar-plan': { 
    id: 'wb-mar-plan', 
    type: 'whiteboard', 
    name: 'March Content Plan', 
    parentId: 'page-mar-26', 
    whiteboardData: DEFAULT_WHITEBOARD_DATA,
    lastEdited: '2h ago',
    isFavorite: true
  }
};

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

export default function App() {
  // --- Navigation State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>(INITIAL_NODES);
  const [activeNodeId, setActiveNodeId] = useState<string>('root'); // Start on Home (root)

  // --- Whiteboard State (Active Board) ---
  // When a whiteboard is active, these represent its internal tabs/workspaces
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');

  // --- Canvas Tools & State ---
  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  // --- UI State ---
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false); // Tool drawer
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Undo/Redo Stacks (Per Whiteboard Session)
  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- DERIVED STATE ---
  // Determine if we are in a special view or a real node
  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  // Resolve what to show in PageView
  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    // Root shows top-level items (parentId === null)
    displayedChildren = Object.values(nodes).filter(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null, icon: '🕒' };
    // Recents shows all items, ideally sorted by date (mock: show all whiteboards/pages)
    displayedChildren = Object.values(nodes).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null, icon: '⭐️' };
    // Favorites shows items with isFavorite === true
    displayedChildren = Object.values(nodes).filter(n => n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = Object.values(nodes).filter(n => n.parentId === activeNodeId);
  } else {
    // Fallback
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  // --- NAVIGATION HANDLERS ---

  const handleNavigate = (id: string) => {
    // If leaving a whiteboard, save its state back to the node tree
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: {
                ...prev[activeNodeId],
                whiteboardData: workspaces
            }
        }));
    }

    const targetNode = nodes[id];
    // If target is a whiteboard, load its data
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }

    setActiveNodeId(id);
    // Reset Canvas State
    setScale(1);
    setHistory([]);
    setFuture([]);
  };

  const handleToggleExpand = (id: string) => {
    setNodes(prev => ({
        ...prev,
        [id]: { ...prev[id], isExpanded: !prev[id].isExpanded }
    }));
  };

  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    soundService.play('success'); // Sound Feedback

    const newId = `${type}-${Date.now()}`;
    // If we are in a special view (like Home/Recents), default parent to null (Root) unless we are inside a folder
    const effectiveParentId = (isSpecialView || !nodes[activeNodeId]) ? null : activeNodeId;

    const newNode: FileSystemNode = {
        id: newId,
        type,
        name: `New ${type.charAt(0).toUpperCase() + type.slice(1)}`,
        parentId: parentId || effectiveParentId,
        isExpanded: true,
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined,
        lastEdited: 'Just now'
    };

    setNodes(prev => {
        // If parent exists and wasn't expanded, expand it
        const parentUpdates = (parentId && prev[parentId]) ? { [parentId]: { ...prev[parentId], isExpanded: true } } : {};
        return { ...prev, ...parentUpdates, [newId]: newNode };
    });

    if (type !== 'folder') {
        handleNavigate(newId);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
    setNodes(prev => ({
        ...prev,
        [id]: { ...prev[id], ...updates }
    }));
  };

  const handleToggleFavorite = (id: string) => {
    soundService.play('toggle'); // Sound Feedback
    setNodes(prev => ({
      ...prev,
      [id]: { ...prev[id], isFavorite: !prev[id].isFavorite }
    }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const newNodes = { ...prev };
          // Recursively delete children
          const deleteRecursively = (nodeId: string) => {
              Object.values(newNodes).filter(n => n.parentId === nodeId).forEach(child => deleteRecursively(child.id));
              delete newNodes[nodeId];
          };
          deleteRecursively(id);
          return newNodes;
      });

      // If we deleted the active node, go to root
      if (activeNodeId === id || !nodes[activeNodeId]) {
          handleNavigate('root');
      }
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
     setNodes(prev => ({
         ...prev,
         [dragId]: { ...prev[dragId], parentId: targetId }
     }));
  };

  const handleExitWhiteboard = () => {
    // Navigate to parent if exists, otherwise fallback to root folder
    if (realNode && realNode.parentId && nodes[realNode.parentId]) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  // --- WHITEBOARD ACTIONS ---

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);

    const updatedWorkspaces = workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    );
    setWorkspaces(updatedWorkspaces);

    // Auto-save to node state (throttled in real app, immediate here for sync)
    setNodes(prev => ({
        ...prev,
        [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces }
    }));
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(prev => prev.slice(0, -1));

    updateCardsNoHistory(previous);
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(prev => prev.slice(1));

    updateCardsNoHistory(next);
  };

  const updateCardsNoHistory = (newCards: CardData[]) => {
      const updated = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  // --- GLOBAL KEYBOARD LISTENERS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);

      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
          if (e.key.toLowerCase() === 't') setActiveTool('TEXT');
          if (e.key.toLowerCase() === 'n') setActiveTool('STICKY');
          if (e.key.toLowerCase() === 'p') setActiveTool('PEN');
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') { e.preventDefault(); handleUndo(); }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') { e.preventDefault(); handleRedo(); }
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, history, future, activeWorkspaceId, isWhiteboardMode]);

  // --- INTERNAL TAB MANAGEMENT (Like Old App.tsx) ---
  const addCard = (type: CardType) => {
    soundService.play('drop'); // Sound Feedback

    let width = 360;
    let height = 200;

    // Custom dimensions for specific types
    if (type === CardType.GRID_PLANNER) { width = 320; height = 500; }
    if (type === CardType.GANTT) { width = 800; height = 400; }
    if (type === CardType.ADS_TEST) { width = 600; height = 500; }

    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - (width / 2),
      y: window.innerHeight / 2 - (height / 2),
      width,
      height, 
      zIndex: type === CardType.GANTT ? 1 : 100, // Gantt spawns as background
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false); // Close drawer after adding
  };

  const addTab = () => {
    soundService.play('drop'); // Sound Feedback
    const newWs: Workspace = {
      id: `tab-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };


  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* --- SIDEBAR --- */}
      {/* Hidden in Whiteboard Mode */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          onNavigate={handleNavigate}
          onToggleExpand={handleToggleExpand}
          onCreateNode={handleCreateNode}
          onToggleFavorite={handleToggleFavorite}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* --- MAIN CONTENT AREA --- */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">

         {/* Toggle Sidebar Button (Float) - Only show in Page View */}
         {!isSidebarOpen && !isWhiteboardMode && (
             <button 
                onClick={() => setIsSidebarOpen(true)}
                className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"
             >
                 <Menu size={16} />
             </button>
         )}

         {/* --- VIEW: WHITEBOARD --- */}
         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#f3f4f6]">

                {/* Canvas */}
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    isSpacePressed={isSpacePressed}
                />

                {/* --- LEFT HOVER TRIGGER ZONE --- */}
                {/* Invisible strip on left edge to auto-open menu */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* --- MENU DRAWER --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[300px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">

                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input 
                                    type="text" 
                                    placeholder="Search tools..." 
                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-9 pr-4 py-2 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 focus:border-[#3A5C34] transition-all outline-none" 
                                    value={searchTerm} 
                                    onChange={(e) => setSearchTerm(e.target.value)} 
                                />
                            </div>
                        </div>

                        {/* Drawer Content */}
                        <div className="flex-1 overflow-y-auto p-5 no-scrollbar space-y-8">

                            {/* Section 1: Essentials (Grid) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Essentials</h3>
                                <div className="grid grid-cols-4 gap-2">
                                    {/* Post: Pink/Burgundy */}
                                    <button onClick={() => addCard(CardType.POST)} className="aspect-square rounded-xl bg-[#FCCAE2] hover:bg-[#ffb4d6] text-[#5F2427] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <FileImage size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Post</span>
                                    </button>
                                    {/* Text: Yellow/Green */}
                                    <button onClick={() => { setActiveTool('TEXT'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#FFD753] hover:bg-[#ffe38a] text-[#3A5C34] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <Type size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Text</span>
                                    </button>
                                    {/* Note: Green/Pink */}
                                    <button onClick={() => { setActiveTool('STICKY'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#3A5C34] hover:bg-[#2d4a29] text-[#FCCAE2] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <StickyNote size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Note</span>
                                    </button>
                                    {/* Draw: Burgundy/Yellow */}
                                    <button onClick={() => { setActiveTool('PEN'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#5F2427] hover:bg-[#4a1c1e] text-[#FFD753] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <PenTool size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Draw</span>
                                    </button>
                                </div>
                            </div>

                            {/* Section 2: Tools & Widgets (List) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Tools & Widgets</h3>
                                <div className="space-y-2">
                                    {/* Chronos: Green/Yellow */}
                                    <button onClick={() => addCard(CardType.GANTT)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#3A5C34]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34] text-[#FFD753] flex items-center justify-center shadow-sm">
                                            <CalendarRange size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">The Chronos</div>
                                            <div className="text-[11px] text-gray-400">Timeline & Gantt View</div>
                                        </div>
                                    </button>

                                    {/* Lab: Burgundy/Pink */}
                                    <button onClick={() => addCard(CardType.ADS_TEST)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#5F2427]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427] text-[#FCCAE2] flex items-center justify-center shadow-sm">
                                            <Beaker size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">The Lab</div>
                                            <div className="text-[11px] text-gray-400">Creative Testing Suite</div>
                                        </div>
                                    </button>

                                    {/* Feed Planner: Yellow/Burgundy */}
                                    <button onClick={() => addCard(CardType.GRID_PLANNER)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#FFD753]/50 hover:bg-[#FFD753]/10 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#FFD753] text-[#5F2427] flex items-center justify-center shadow-sm">
                                            <LayoutGrid size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">Feed Planner</div>
                                            <div className="text-[11px] text-gray-400">Visually plan Instagram grid</div>
                                        </div>
                                    </button>

                                    {/* Oracle AI: Pink/Green */}
                                    <button onClick={() => addCard(CardType.STRATEGY_AI)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#FCCAE2]/50 hover:bg-[#FCCAE2]/20 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#FCCAE2] text-[#3A5C34] flex items-center justify-center shadow-sm">
                                            <Sparkles size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">Oracle AI</div>
                                            <div className="text-[11px] text-gray-400">Generate creative strategies</div>
                                        </div>
                                    </button>

                                    {/* Performance: Green Tint */}
                                    <button onClick={() => addCard(CardType.ANALYTICS)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#3A5C34]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/10 text-[#3A5C34] flex items-center justify-center">
                                            <TrendingUp size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">Performance</div>
                                            <div className="text-[11px] text-gray-400">Track campaign KPIs</div>
                                        </div>
                                    </button>

                                    {/* Pinterest: Burgundy Tint */}
                                    <button onClick={() => addCard(CardType.PINTEREST)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#5F2427]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427]/10 text-[#5F2427] flex items-center justify-center">
                                            <ImageIcon size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">Pinterest</div>
                                            <div className="text-[11px] text-gray-400">Import boards & pins</div>
                                        </div>
                                    </button>
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Internal Tabs (Workspaces) - Bottom Left */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-2 pl-2 pr-4 pointer-events-auto max-w-full">
                    {workspaces.map(ws => {
                        const isActive = activeWorkspaceId === ws.id;
                        return (
                        <div key={ws.id} className="relative group flex-shrink-0">
                            <button onClick={() => setActiveWorkspaceId(ws.id)} className={`relative h-11 px-4 min-w-[100px] max-w-[180px] flex items-center gap-2.5 rounded-full transition-all duration-300 select-none bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] ${isActive ? 'text-[#3A5C34] font-bold scale-100 z-10 ring-1 ring-[#3A5C34]/30' : 'text-gray-500 hover:text-[#5F2427] hover:scale-[1.02] active:scale-[0.98] z-0 opacity-70 hover:opacity-100'}`}>
                            <div className={`w-2 h-2 rounded-full shadow-sm transition-transform duration-300 border border-white/50 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`} style={{ backgroundColor: ws.color || '#3A5C34' }} />
                            <span className="truncate text-[13px] tracking-tight">{ws.name}</span>
                            {isActive && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="ml-auto p-1 -mr-1 rounded-full hover:bg-black/5 text-[#3A5C34] cursor-pointer transition-colors"><ChevronDown size={12} strokeWidth={2.5} /></div>}
                            </button>
                        </div>
                        );
                    })}
                    <button onClick={addTab} className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"><Plus size={20} strokeWidth={2.5} /></button>
                    </div>
                </div>

                 {/* Top Right Control Cluster: Breadcrumbs + Scale/Undo + Exit */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">

                    {/* 1. Breadcrumb Pill */}
                    <div className="hidden md:flex h-11 px-5 items-center gap-2 rounded-full bg-white/80 backdrop-blur-xl border border-white/60 shadow-sm select-none">
                        <span className="text-[13px] font-medium text-gray-500 max-w-[120px] truncate">{realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}</span>
                        <span className="text-gray-300">/</span>
                        <span className="text-[13px] font-bold text-[#3A5C34] max-w-[160px] truncate">{displayedNode.name}</span>
                    </div>

                    {/* 2. Scale & Undo/Redo */}
                    <div className="h-11 px-2 flex items-center gap-1 rounded-full bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)]">
                        <div className="px-3 text-[13px] font-bold text-gray-600 select-none w-[60px] text-center tracking-tight">{Math.round(scale * 100)}%</div>
                        <div className="w-px h-4 bg-gray-400/30"></div>
                        <button onClick={handleUndo} disabled={history.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Undo2 size={16} strokeWidth={2.5} /></button>
                        <button onClick={handleRedo} disabled={future.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Redo2 size={16} strokeWidth={2.5} /></button>
                    </div>

                    {/* 3. Exit Button */}
                    <button 
                        onClick={handleExitWhiteboard}
                        className="h-11 w-11 rounded-full bg-white/90 backdrop-blur-xl border border-white/60 shadow-sm flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:bg-gray-100 transition-all active:scale-95"
                        title="Exit Whiteboard"
                    >
                        <Home size={20} />
                    </button>
                </div>

                {/* Tools Drawer Button (Visual indicator for the hover zone) */}
                <div className="absolute top-6 left-6 z-40">
                    <button onClick={() => setIsDrawerOpen(true)} className="w-12 h-12 rounded-full bg-[#3A5C34] shadow-lg border border-white/20 flex items-center justify-center text-white hover:scale-110 transition-all">
                       <Plus size={24} strokeWidth={1.5} />
                    </button>
                </div>

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}

                {/* Tab Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <input type="text" className="w-full bg-white/50 border border-black/5 rounded-lg px-2.5 py-1.5 text-[13px] font-medium text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#3A5C34]/20 transition-all" placeholder="Tab Name" value={workspaces.find(w => w.id === colorPickerState?.id)?.name || ''} onChange={(e) => updateTabName(colorPickerState!.id, e.target.value)} autoFocus />
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}
            </div>
         ) : (
            /* --- VIEW: PAGE / FOLDER DASHBOARD --- */
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={handleToggleFavorite}
            />
         )}
      </div>

    </div>
  );
}

