                            </button>
                        </div>
                        );
                    })}
                    <button onClick={addTab} className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"><Plus size={20} strokeWidth={2.5} /></button>
                    </div>
                </div>

                 {/* Top Right Control Cluster: Breadcrumbs + Scale/Undo + Exit */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">

                    {/* 1. Breadcrumb Pill */}
                    <div className="hidden md:flex h-11 px-5 items-center gap-2 rounded-full bg-white/80 backdrop-blur-xl border border-white/60 shadow-sm select-none">
                        <span className="text-[13px] font-medium text-gray-500 max-w-[120px] truncate">{realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}</span>
                        <span className="text-gray-300">/</span>
                        <span className="text-[13px] font-bold text-[#3A5C34] max-w-[160px] truncate">{displayedNode.name}</span>
                    </div>

                    {/* 2. Scale & Undo/Redo */}
                    <div className="h-11 px-2 flex items-center gap-1 rounded-full bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)]">
                        <div className="px-3 text-[13px] font-bold text-gray-600 select-none w-[60px] text-center tracking-tight">{Math.round(scale * 100)}%</div>
                        <div className="w-px h-4 bg-gray-400/30"></div>
                        <button onClick={handleUndo} disabled={history.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Undo2 size={16} strokeWidth={2.5} /></button>
                        <button onClick={handleRedo} disabled={future.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Redo2 size={16} strokeWidth={2.5} /></button>
                    </div>

                    {/* 3. Exit Button */}
                    <button 
                        onClick={handleExitWhiteboard}
                        className="h-11 w-11 rounded-full bg-white/90 backdrop-blur-xl border border-white/60 shadow-sm flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:bg-gray-100 transition-all active:scale-95"
                        title="Exit Whiteboard"
                    >
                        <Home size={20} />
                    </button>
                </div>

                {/* Tools Drawer Button (Visual indicator for the hover zone) */}
                <div className="absolute top-6 left-6 z-40">
                    <button onClick={() => setIsDrawerOpen(true)} className="w-12 h-12 rounded-full bg-[#3A5C34] shadow-lg border border-white/20 flex items-center justify-center text-white hover:scale-110 transition-all">
                       <Plus size={24} strokeWidth={1.5} />
                    </button>
                </div>

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}

                {/* Tab Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <input type="text" className="w-full bg-white/50 border border-black/5 rounded-lg px-2.5 py-1.5 text-[13px] font-medium text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#3A5C34]/20 transition-all" placeholder="Tab Name" value={workspaces.find(w => w.id === colorPickerState?.id)?.name || ''} onChange={(e) => updateTabName(colorPickerState!.id, e.target.value)} autoFocus />
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}
            </div>
         ) : (
            /* --- VIEW: PAGE / FOLDER DASHBOARD --- */
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={handleToggleFavorite}
            />
         )}
      </div>

    </div>
  );
}

import React, { useState } from 'react';
import { FileSystemNode } from '../types';
import { 
  Clock, 
  Star, 
  Plus, 
  Folder, 
  Search, 
  Grid2X2, 
  List as ListIcon, 
  LayoutTemplate,
  MoreHorizontal
} from 'lucide-react';

interface PageViewProps {
  node: FileSystemNode;
  childNodes: FileSystemNode[];
  onNavigate: (id: string) => void;
  onCreateWhiteboard: () => void;
  onCreateFolder: () => void;
  onToggleFavorite?: (id: string) => void;
}

export const PageView: React.FC<PageViewProps> = ({
  node,
  childNodes,
  onNavigate,
  onCreateWhiteboard,
  onCreateFolder,
  onToggleFavorite
}) => {
  const [searchQuery, setSearchQuery] = useState("");

  const whiteboards = childNodes.filter(n => n.type === 'whiteboard');
  const folders = childNodes.filter(n => n.type !== 'whiteboard');

  const filteredWhiteboards = whiteboards.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));
  const filteredFolders = folders.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));

  // Don't show "Create" buttons in special views like Recents/Favorites unless appropriate (optional UX choice)
  // For now, allow creation in Root, but maybe restrict in Recents/Favorites if they are read-only views
  const isSpecialView = ['recents', 'favorites'].includes(node.id);

  return (
    <div className="flex-1 bg-white h-full overflow-y-auto no-scrollbar font-sans">
      <div className="max-w-[1400px] mx-auto p-8 lg:p-12">

        {/* --- HEADER --- */}
        <header className="flex flex-col gap-6 mb-10">

          {/* Top Row: Breadcrumbs / Title */}
          <div className="flex flex-col gap-2">
             <div className="flex items-center gap-2 text-[13px] font-medium text-gray-400">
                <span>Workspace</span>
                <span>/</span>
                <span className="text-gray-900">{node.name}</span>
             </div>
             <h1 className="text-[32px] font-bold text-gray-900 tracking-tight leading-tight flex items-center gap-3">
               {node.icon && <span className="text-[32px]">{node.icon}</span>}
               {node.name}
             </h1>
          </div>

          {/* Controls Row: Search & Actions */}
          <div className="flex items-center justify-between gap-4">
             {/* Search */}
             <div className="relative flex-1 max-w-sm group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3A5C34] transition-colors" size={16} />
                <input 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full h-10 bg-gray-50 border border-gray-200 rounded-lg pl-9 pr-4 text-[14px] text-gray-900 placeholder-gray-400 focus:ring-2 focus:ring-[#3A5C34]/20 focus:border-[#3A5C34] transition-all outline-none"
                  placeholder="Filter items..."
                />
             </div>

             {/* Actions */}
             <div className="flex items-center gap-3">
                <div className="flex items-center bg-gray-50 p-0.5 rounded-lg border border-gray-200 mr-2">
                    <button className="p-1.5 bg-white rounded-md shadow-sm text-gray-900"><Grid2X2 size={16}/></button>
                    <button className="p-1.5 text-gray-400 hover:text-gray-600"><ListIcon size={16}/></button>
                </div>

                {!isSpecialView && (
                  <>
                    <button 
                      onClick={onCreateFolder}
                      className="h-9 px-4 rounded-lg bg-white border border-gray-200 text-gray-700 font-medium text-[13px] hover:bg-gray-50 hover:border-gray-300 transition-all active:scale-95 flex items-center gap-2 shadow-sm"
                    >
                      <Folder size={14} className="text-gray-500" />
                      New Folder
                    </button>

                    <button 
                      onClick={onCreateWhiteboard}
                      className="h-9 px-4 rounded-lg bg-[#3A5C34] text-white font-medium text-[13px] hover:bg-[#2d4a29] transition-all active:scale-95 flex items-center gap-2 shadow-md shadow-green-900/10"
                    >
                      <Plus size={14} />
                      New Whiteboard
                    </button>
                  </>
                )}
             </div>
          </div>
        </header>

        {/* --- SECTIONS --- */}

        {/* 1. FOLDERS */}
        {(filteredFolders.length > 0 || (!searchQuery && !isSpecialView)) && (
            <section className="mb-12">
                <div className="flex items-center gap-2 mb-4">
                    <h2 className="text-[14px] font-semibold text-gray-900">Folders</h2>
                    <span className="px-1.5 py-0.5 rounded-full bg-gray-100 text-[11px] font-bold text-gray-500">{filteredFolders.length}</span>
                </div>

                {filteredFolders.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                        {filteredFolders.map(folder => (
                            <button 
                                key={folder.id}
                                onClick={() => onNavigate(folder.id)}
                                className="group flex flex-col gap-3 p-4 rounded-xl border border-gray-200 bg-white hover:border-[#3A5C34]/40 hover:shadow-md hover:shadow-[#3A5C34]/5 transition-all text-left relative h-full"
                            >
                                <div className="flex items-center gap-3">
                                    <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform ${folder.icon ? 'bg-gray-50' : 'bg-[#FCCAE2]/20 text-[#3A5C34]'}`}>
                                        {folder.icon ? (
                                            <span className="text-[20px]">{folder.icon}</span>
                                        ) : (
                                            <Folder size={18} fill="currentColor" className="opacity-90" />
                                        )}
                                    </div>
                                    <div className="min-w-0 flex-1">
                                        <h3 className="text-[14px] font-bold text-gray-900 truncate group-hover:text-[#3A5C34] transition-colors">{folder.name}</h3>
                                    </div>
                                </div>

                                {folder.description && (
                                    <p className="text-[12px] text-gray-500 leading-relaxed line-clamp-2 min-h-[32px]">
                                        {folder.description}
                                    </p>
                                )}

                                <div className="mt-auto pt-2 text-[11px] text-gray-400 font-medium">
                                    0 items
                                </div>

                                {onToggleFavorite && (
                                  <div 
                                    className="absolute top-2 right-2 p-1.5 rounded-full hover:bg-gray-100 text-gray-300 hover:text-yellow-400 transition-all opacity-0 group-hover:opacity-100"
                                    onClick={(e) => { e.stopPropagation(); onToggleFavorite(folder.id); }}
                                  >
                                    <Star size={14} fill={folder.isFavorite ? "currentColor" : "none"} className={folder.isFavorite ? "text-[#FFD753]" : ""} />
                                  </div>
                                )}
                            </button>
                        ))}
                    </div>
                ) : (
                    <div className="text-gray-400 text-[13px] italic py-8 border border-dashed border-gray-200 rounded-xl flex flex-col items-center justify-center bg-gray-50/30">
                        <Folder size={24} className="mb-2 opacity-20" />
                        No folders found
                    </div>
                )}
            </section>
        )}

        {/* 2. WHITEBOARDS */}
        <section>
            <div className="flex items-center gap-2 mb-4">
                <h2 className="text-[14px] font-semibold text-gray-900">Whiteboards</h2>
                <span className="px-1.5 py-0.5 rounded-full bg-gray-100 text-[11px] font-bold text-gray-500">{filteredWhiteboards.length}</span>
            </div>

            {filteredWhiteboards.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                    {/* Create New Card (Inline) - Only show if allowed */}
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            className="group flex flex-col items-center justify-center gap-3 bg-gray-50 rounded-2xl border border-dashed border-gray-300 hover:border-[#3A5C34] hover:bg-[#FCCAE2]/20 transition-all cursor-pointer aspect-[4/3]"
                        >
                            <div className="w-12 h-12 rounded-full bg-white shadow-sm border border-gray-200 flex items-center justify-center text-gray-400 group-hover:text-[#3A5C34] group-hover:scale-110 transition-all duration-300">
                                <Plus size={20} />
                            </div>
                            <span className="text-[13px] font-medium text-gray-500 group-hover:text-[#3A5C34]">Create New</span>
                        </button>
                    )}

                    {filteredWhiteboards.map(wb => (
                        <div 
                          key={wb.id}
                          onClick={() => onNavigate(wb.id)}
                          className="group relative flex flex-col bg-white rounded-2xl border border-gray-200 overflow-hidden hover:border-[#FFD753] hover:shadow-lg hover:shadow-[#FFD753]/20 transition-all duration-300 cursor-pointer"
                        >
                            {/* Preview Area - Light & Clean */}
                            <div className="aspect-[4/3] bg-white relative overflow-hidden border-b border-gray-50">
                                {/* Dot Pattern Background */}
                                <div className="absolute inset-0 opacity-[0.4]" 
                                     style={{ backgroundImage: 'radial-gradient(#CBD5E1 1px, transparent 1px)', backgroundSize: '16px 16px' }}>
                                </div>

                                {/* Abstract Content Hint */}
                                <div className="absolute inset-6 bg-white rounded-lg shadow-sm border border-gray-100 group-hover:scale-105 group-hover:-translate-y-1 transition-transform duration-500 flex flex-col p-3 gap-2">
                                    <div className="w-1/3 h-2 bg-gray-100 rounded-full"></div>
                                    <div className="flex gap-2">
                                        <div className="w-8 h-8 rounded bg-green-50/50 border border-green-100"></div>
                                        <div className="w-8 h-8 rounded bg-pink-50/50 border border-pink-100"></div>
                                    </div>
                                </div>

                                {/* Hover Overlay Button */}
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-white/30 backdrop-blur-[1px]">
                                    <div className="px-4 py-1.5 bg-[#3A5C34] border border-[#3A5C34] shadow-md rounded-full text-[12px] font-medium text-white">
                                        Open Board
                                    </div>
                                </div>
                            </div>

                            {/* Info Footer */}
                            <div className="p-4 flex flex-col gap-1">
                                <div className="flex items-center justify-between gap-2">
                                    <h3 className="text-[14px] font-semibold text-gray-900 truncate flex items-center gap-2">
                                        {wb.icon && <span>{wb.icon}</span>}
                                        {wb.name}
                                    </h3>
                                    {onToggleFavorite && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onToggleFavorite(wb.id); }}
                                            className={`hover:text-[#FFD753] transition-opacity shrink-0 ${wb.isFavorite ? 'text-[#FFD753] opacity-100' : 'text-gray-300 opacity-0 group-hover:opacity-100'}`}
                                        >
                                            <Star size={14} fill={wb.isFavorite ? "currentColor" : "none"} />
                                        </button>
                                    )}
                                </div>
                                <div className="flex items-center justify-between mt-1">
                                    <span className="text-[11px] text-gray-400 flex items-center gap-1">
                                        <Clock size={10} /> {wb.lastEdited || 'Just now'}
                                    </span>
                                    <div className="flex -space-x-1.5">
                                        <div className="w-5 h-5 rounded-full bg-[#3A5C34]/10 border border-white flex items-center justify-center text-[8px] font-bold text-[#3A5C34]">JD</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center py-16 text-center border border-dashed border-gray-200 rounded-2xl bg-gray-50/30">
                    <div className="w-12 h-12 bg-white rounded-full shadow-sm flex items-center justify-center mb-3">
                        <LayoutTemplate size={20} className="text-gray-400" />
                    </div>
                    <p className="text-[14px] font-medium text-gray-900">No whiteboards created yet</p>
                    <p className="text-[12px] text-gray-500 mb-4">Start your first project in this folder.</p>
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            className="px-4 py-2 rounded-full bg-white border border-gray-200 text-[13px] font-medium text-gray-700 shadow-sm hover:bg-gray-50 transition-all"
                        >
                            Create Whiteboard
                        </button>
                    )}
                </div>
            )}
        </section>

      </div>
    </div>
  );
};

