                                    <button onClick={() => { setActiveTool('TEXT'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#FFD753] hover:bg-[#ffe38a] text-[#3A5C34] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
