  }
};

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

export default function App() {
  // --- Navigation State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>(INITIAL_NODES);
  const [activeNodeId, setActiveNodeId] = useState<string>('root'); // Start on Home (root)

  // --- Whiteboard State (Active Board) ---
  // When a whiteboard is active, these represent its internal tabs/workspaces
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');

  // --- Canvas Tools & State ---
  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  // --- UI State ---
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false); // Tool drawer
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Undo/Redo Stacks (Per Whiteboard Session)
  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- DERIVED STATE ---
  // Determine if we are in a special view or a real node
  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  // Resolve what to show in PageView
  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];

  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return Object.values(nodes).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    // Root shows top-level items (parentId === null)
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    // Recents shows all items, ideally sorted by date (mock: show all whiteboards/pages)
    displayedChildren = Object.values(nodes).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    // Favorites shows items with isFavorite === true
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    // Fallback
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  // --- NAVIGATION HANDLERS ---

  const handleNavigate = (id: string) => {
    // If leaving a whiteboard, save its state back to the node tree
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: {
                ...prev[activeNodeId],
                whiteboardData: workspaces
            }
        }));
    }

    const targetNode = nodes[id];
    // If target is a whiteboard, load its data
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }

    setActiveNodeId(id);
    // Reset Canvas State
    setScale(1);
    setHistory([]);
    setFuture([]);
  };

  const handleToggleExpand = (id: string) => {
    setNodes(prev => ({
        ...prev,
        [id]: { ...prev[id], isExpanded: !prev[id].isExpanded }
    }));
  };

  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    soundService.play('success'); // Sound Feedback

    const newId = `${type}-${Date.now()}`;
    // If we are in a special view (like Home/Recents), default parent to null (Root) unless we are inside a folder
    const effectiveParentId = (isSpecialView || !nodes[activeNodeId]) ? null : activeNodeId;

    // Find highest order to append
    const siblings = Object.values(nodes).filter(n => n.parentId === effectiveParentId);
    const maxOrder = siblings.length > 0 ? Math.max(...siblings.map(n => n.order || 0)) : -1;

    const newNode: FileSystemNode = {
        id: newId,
        type,
        name: `New ${type.charAt(0).toUpperCase() + type.slice(1)}`,
        parentId: parentId || effectiveParentId,
        isExpanded: true,
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined,
        lastEdited: 'Just now',
        order: maxOrder + 1
    };

    setNodes(prev => {
        // If parent exists and wasn't expanded, expand it
        const parentUpdates = (parentId && prev[parentId]) ? { [parentId]: { ...prev[parentId], isExpanded: true } } : {};
        return { ...prev, ...parentUpdates, [newId]: newNode };
    });

    if (type !== 'folder') {
        handleNavigate(newId);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
    setNodes(prev => ({
        ...prev,
        [id]: { ...prev[id], ...updates }
    }));
  };

  const handleToggleFavorite = (id: string) => {
    soundService.play('toggle'); // Sound Feedback
    setNodes(prev => ({
      ...prev,
      [id]: { ...prev[id], isFavorite: !prev[id].isFavorite }
    }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const newNodes = { ...prev };
          // Recursively delete children
          const deleteRecursively = (nodeId: string) => {
              Object.values(newNodes).filter(n => n.parentId === nodeId).forEach(child => deleteRecursively(child.id));
              delete newNodes[nodeId];
          };
          deleteRecursively(id);
          return newNodes;
      });

      // If we deleted the active node, go to root
      if (activeNodeId === id || !nodes[activeNodeId]) {
          handleNavigate('root');
      }
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
     setNodes(prev => ({
         ...prev,
         [dragId]: { ...prev[dragId], parentId: targetId }
     }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
    const dragNode = nodes[dragId];
    const targetNode = nodes[targetId];

    // Safety checks: both must exist, must be siblings, and preferably same type to keep grids clean (though logic allows mixed)
    // We strictly enforce reordering only within same parent.
    if (!dragNode || !targetNode || dragNode.parentId !== targetNode.parentId) return;

    // Get all siblings, sorted by current order
    const siblings = Object.values(nodes)
        .filter(n => n.parentId === dragNode.parentId && n.type === dragNode.type) // Filter by type to keep folders/whiteboards separate lists sorted
        .sort((a, b) => (a.order || 0) - (b.order || 0));

    const dragIndex = siblings.findIndex(n => n.id === dragId);
    const targetIndex = siblings.findIndex(n => n.id === targetId);

    if (dragIndex === -1 || targetIndex === -1 || dragIndex === targetIndex) return;

    // Rearrange array
    const newSiblings = [...siblings];
    newSiblings.splice(dragIndex, 1);
    newSiblings.splice(targetIndex, 0, dragNode);

    // Apply new order indices
    const updates: Record<string, Partial<FileSystemNode>> = {};
    newSiblings.forEach((node, index) => {
        if ((node.order || 0) !== index) {
            updates[node.id] = { order: index };
        }
    });

    if (Object.keys(updates).length > 0) {
        setNodes(prev => {
            const next = { ...prev };
            Object.entries(updates).forEach(([id, update]) => {
                next[id] = { ...next[id], ...update };
            });
            return next;
        });
        soundService.play('snap');
    }
  };

  const handleExitWhiteboard = () => {
    // Navigate to parent if exists, otherwise fallback to root folder
    if (realNode && realNode.parentId && nodes[realNode.parentId]) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  // --- WHITEBOARD ACTIONS ---

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);

    const updatedWorkspaces = workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    );
    setWorkspaces(updatedWorkspaces);

    // Auto-save to node state (throttled in real app, immediate here for sync)
    setNodes(prev => ({
        ...prev,
        [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces }
    }));
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(prev => prev.slice(0, -1));

    updateCardsNoHistory(previous);
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(prev => prev.slice(1));

    updateCardsNoHistory(next);
  };

  const updateCardsNoHistory = (newCards: CardData[]) => {
      const updated = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  // --- GLOBAL KEYBOARD LISTENERS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);

      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
          if (e.key.toLowerCase() === 't') setActiveTool('TEXT');
          if (e.key.toLowerCase() === 'n') setActiveTool('STICKY');
          if (e.key.toLowerCase() === 'p') setActiveTool('PEN');
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') { e.preventDefault(); handleUndo(); }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') { e.preventDefault(); handleRedo(); }
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, history, future, activeWorkspaceId, isWhiteboardMode]);

  // --- INTERNAL TAB MANAGEMENT (Like Old App.tsx) ---
  const addCard = (type: CardType) => {
    soundService.play('drop'); // Sound Feedback

    let width = 360;
    let height = 200;

    // Custom dimensions for specific types
    if (type === CardType.GRID_PLANNER) { width = 320; height = 500; }
    if (type === CardType.GANTT) { width = 800; height = 400; }
    if (type === CardType.ADS_TEST) { width = 600; height = 500; }

    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - (width / 2),
      y: window.innerHeight / 2 - (height / 2),
      width,
      height, 
      zIndex: type === CardType.GANTT ? 1 : 100, // Gantt spawns as background
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false); // Close drawer after adding
  };

  const addTab = () => {
    soundService.play('drop'); // Sound Feedback
    const newWs: Workspace = {
      id: `tab-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };


  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* --- SIDEBAR --- */}
      {/* Hidden in Whiteboard Mode */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          onNavigate={handleNavigate}
          onToggleExpand={handleToggleExpand}
          onCreateNode={handleCreateNode}
          onToggleFavorite={handleToggleFavorite}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* --- MAIN CONTENT AREA --- */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">

         {/* Toggle Sidebar Button (Float) - Only show in Page View */}
         {!isSidebarOpen && !isWhiteboardMode && (
             <button 
                onClick={() => setIsSidebarOpen(true)}
                className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"
             >
                 <Menu size={16} />
             </button>
         )}

         {/* --- VIEW: WHITEBOARD --- */}
         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#f3f4f6]">

                {/* Canvas */}
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    isSpacePressed={isSpacePressed}
                />

                {/* --- LEFT HOVER TRIGGER ZONE --- */}
                {/* Invisible strip on left edge to auto-open menu */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* --- MENU DRAWER --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[300px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">

                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input 
                                    type="text" 
                                    placeholder="Search tools..." 
                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-9 pr-4 py-2 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 focus:border-[#3A5C34] transition-all outline-none" 
                                    value={searchTerm} 
                                    onChange={(e) => setSearchTerm(e.target.value)} 
                                />
                            </div>
                        </div>

                        {/* Drawer Content */}
                        <div className="flex-1 overflow-y-auto p-5 no-scrollbar space-y-8">

                            {/* Section 1: Essentials (Grid) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Essentials</h3>
                                <div className="grid grid-cols-4 gap-2">
                                    {/* Post: Pink/Burgundy */}
                                    <button onClick={() => addCard(CardType.POST)} className="aspect-square rounded-xl bg-[#FCCAE2] hover:bg-[#ffb4d6] text-[#5F2427] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <FileImage size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Post</span>
                                    </button>
                                    {/* Text: Yellow/Green */}
                                    <button onClick={() => { setActiveTool('TEXT'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#FFD753] hover:bg-[#ffe38a] text-[#3A5C34] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <Type size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Text</span>
                                    </button>
                                    {/* Note: Green/Pink */}
                                    <button onClick={() => { setActiveTool('STICKY'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#3A5C34] hover:bg-[#2d4a29] text-[#FCCAE2] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <StickyNote size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Note</span>
                                    </button>
                                    {/* Draw: Burgundy/Yellow */}
                                    <button onClick={() => { setActiveTool('PEN'); setIsDrawerOpen(false); }} className="aspect-square rounded-xl bg-[#5F2427] hover:bg-[#4a1c1e] text-[#FFD753] flex flex-col items-center justify-center gap-1 transition-all hover:scale-105 active:scale-95 group">
                                        <PenTool size={20} className="group-hover:-translate-y-0.5 transition-transform" />
                                        <span className="text-[9px] font-semibold">Draw</span>
                                    </button>
                                </div>
                            </div>

                            {/* Section 2: Tools & Widgets (List) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Tools & Widgets</h3>
                                <div className="space-y-2">
                                    {/* Chronos: Green/Yellow */}
                                    <button onClick={() => addCard(CardType.GANTT)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#3A5C34]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34] text-[#FFD753] flex items-center justify-center shadow-sm">
                                            <CalendarRange size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">The Chronos</div>
                                            <div className="text-[11px] text-gray-400">Timeline & Gantt View</div>
                                        </div>
                                    </button>

                                    {/* Lab: Burgundy/Pink */}
                                    <button onClick={() => addCard(CardType.ADS_TEST)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#5F2427]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427] text-[#FCCAE2] flex items-center justify-center shadow-sm">
                                            <Beaker size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">The Lab</div>
                                            <div className="text-[11px] text-gray-400">Creative Testing Suite</div>
                                        </div>
                                    </button>

                                    {/* Feed Planner: Yellow/Burgundy */}
                                    <button onClick={() => addCard(CardType.GRID_PLANNER)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#FFD753]/50 hover:bg-[#FFD753]/10 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#FFD753] text-[#5F2427] flex items-center justify-center shadow-sm">
                                            <LayoutGrid size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">Feed Planner</div>
                                            <div className="text-[11px] text-gray-400">Visually plan Instagram grid</div>
                                        </div>
                                    </button>

                                    {/* Oracle AI: Pink/Green */}
                                    <button onClick={() => addCard(CardType.STRATEGY_AI)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#FCCAE2]/50 hover:bg-[#FCCAE2]/20 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#FCCAE2] text-[#3A5C34] flex items-center justify-center shadow-sm">
                                            <Sparkles size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">Oracle AI</div>
                                            <div className="text-[11px] text-gray-400">Generate creative strategies</div>
                                        </div>
                                    </button>

                                    {/* Performance: Green Tint */}
                                    <button onClick={() => addCard(CardType.ANALYTICS)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#3A5C34]/30 hover:bg-[#3A5C34]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/10 text-[#3A5C34] flex items-center justify-center">
                                            <TrendingUp size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#3A5C34]">Performance</div>
                                            <div className="text-[11px] text-gray-400">Track campaign KPIs</div>
                                        </div>
                                    </button>

                                    {/* Pinterest: Burgundy Tint */}
                                    <button onClick={() => addCard(CardType.PINTEREST)} className="w-full text-left p-3 rounded-xl border border-gray-100 hover:border-[#5F2427]/30 hover:bg-[#5F2427]/5 transition-all flex items-center gap-3 group active:scale-[0.98]">
                                        <div className="w-8 h-8 rounded-lg bg-[#5F2427]/10 text-[#5F2427] flex items-center justify-center">
                                            <ImageIcon size={16} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="text-[13px] font-semibold text-gray-700 group-hover:text-[#5F2427]">Pinterest</div>
                                            <div className="text-[11px] text-gray-400">Import boards & pins</div>
                                        </div>
                                    </button>
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Internal Tabs (Workspaces) - Bottom Left */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-2 pl-2 pr-4 pointer-events-auto max-w-full">
                    {workspaces.map(ws => {
                        const isActive = activeWorkspaceId === ws.id;
                        return (
                        <div key={ws.id} className="relative group flex-shrink-0">
                            <button onClick={() => setActiveWorkspaceId(ws.id)} className={`relative h-11 px-4 min-w-[100px] max-w-[180px] flex items-center gap-2.5 rounded-full transition-all duration-300 select-none bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] ${isActive ? 'text-[#3A5C34] font-bold scale-100 z-10 ring-1 ring-[#3A5C34]/30' : 'text-gray-500 hover:text-[#5F2427] hover:scale-[1.02] active:scale-[0.98] z-0 opacity-70 hover:opacity-100'}`}>
                            <div className={`w-2 h-2 rounded-full shadow-sm transition-transform duration-300 border border-white/50 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`} style={{ backgroundColor: ws.color || '#3A5C34' }} />
                            <span className="truncate text-[13px] tracking-tight">{ws.name}</span>
                            {isActive && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="ml-auto p-1 -mr-1 rounded-full hover:bg-black/5 text-[#3A5C34] cursor-pointer transition-colors"><ChevronDown size={12} strokeWidth={2.5} /></div>}
                            </button>
                        </div>
                        );
                    })}
                    <button onClick={addTab} className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"><Plus size={20} strokeWidth={2.5} /></button>
                    </div>
                </div>

                 {/* Top Right Control Cluster: Breadcrumbs + Scale/Undo + Exit */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">

                    {/* OrbitLogo removed from here */}

                    {/* 1. Breadcrumb Pill */}
                    <div className="hidden md:flex h-11 px-5 items-center gap-2 rounded-full bg-white/80 backdrop-blur-xl border border-white/60 shadow-sm select-none">
                        <span className="text-[13px] font-medium text-gray-500 max-w-[120px] truncate">{realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}</span>
                        <span className="text-gray-300">/</span>
                        <span className="text-[13px] font-bold text-[#3A5C34] max-w-[160px] truncate">{displayedNode.name}</span>
                    </div>

                    {/* 2. Scale & Undo/Redo */}
                    <div className="h-11 px-2 flex items-center gap-1 rounded-full bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)]">
                        <div className="px-3 text-[13px] font-bold text-gray-600 select-none w-[60px] text-center tracking-tight">{Math.round(scale * 100)}%</div>
                        <div className="w-px h-4 bg-gray-400/30"></div>
                        <button onClick={handleUndo} disabled={history.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Undo2 size={16} strokeWidth={2.5} /></button>
                        <button onClick={handleRedo} disabled={future.length === 0} className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 hover:bg-white/50 hover:text-[#3A5C34] disabled:opacity-30 transition-all"><Redo2 size={16} strokeWidth={2.5} /></button>
                    </div>

                    {/* 3. Exit Button */}
                    <button 
                        onClick={handleExitWhiteboard}
                        className="h-11 w-11 rounded-full bg-white/90 backdrop-blur-xl border border-white/60 shadow-sm flex items-center justify-center text-gray-500 hover:text-[#3A5C34] hover:bg-gray-100 transition-all active:scale-95"
                        title="Exit Whiteboard"
                    >
                        <Home size={20} />
                    </button>
                </div>

                {/* Tools Drawer Button (Visual indicator for the hover zone) */}
                <div className="absolute top-6 left-6 z-40">
                    <button onClick={() => setIsDrawerOpen(true)} className="w-12 h-12 rounded-full bg-[#3A5C34] shadow-lg border border-white/20 flex items-center justify-center text-white hover:scale-110 transition-all">
                       <Plus size={24} strokeWidth={1.5} />
                    </button>
                </div>

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}

                {/* Tab Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <input type="text" className="w-full bg-white/50 border border-black/5 rounded-lg px-2.5 py-1.5 text-[13px] font-medium text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#3A5C34]/20 transition-all" placeholder="Tab Name" value={workspaces.find(w => w.id === colorPickerState?.id)?.name || ''} onChange={(e) => updateTabName(colorPickerState!.id, e.target.value)} autoFocus />
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}
            </div>
         ) : (
            /* --- VIEW: PAGE / FOLDER DASHBOARD --- */
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={handleToggleFavorite}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
            />
         )}
      </div>

    </div>
  );
}

import React, { useState } from 'react';
import { FileSystemNode } from '../types';
import { OrbitLogo } from './ui/OrbitLogo';
import { 
  Clock, 
  Star, 
  Plus, 
  Folder, 
  Search, 
  Grid2X2, 
  List as ListIcon, 
  LayoutTemplate,
  MoreHorizontal
} from 'lucide-react';

interface PageViewProps {
  node: FileSystemNode;
  childNodes: FileSystemNode[];
  onNavigate: (id: string) => void;
  onCreateWhiteboard: () => void;
  onCreateFolder: () => void;
  onToggleFavorite?: (id: string) => void;
  onUpdateNode: (id: string, updates: Partial<FileSystemNode>) => void;
  onReorderNode?: (dragId: string, targetId: string) => void;
}

// --- COLOR UTILS ---
// Deterministically assign a brand color theme based on the ID string
const getBrandTheme = (id: string) => {
  const themes = [
    // Yellow Theme
    { 
      bg: 'bg-[#FFD753]/20', 
      text: 'text-[#b89514]', 
      border: 'hover:border-[#FFD753]', 
      icon: '#d9b01c',
      shadow: 'hover:shadow-[#FFD753]/20'
    },
    // Green Theme
    { 
      bg: 'bg-[#3A5C34]/10', 
      text: 'text-[#3A5C34]', 
      border: 'hover:border-[#3A5C34]', 
      icon: '#3A5C34',
      shadow: 'hover:shadow-[#3A5C34]/20'
    },
    // Pink Theme
    { 
      bg: 'bg-[#FCCAE2]/40', 
      text: 'text-[#5F2427]', 
      border: 'hover:border-[#FCCAE2]', 
      icon: '#5F2427',
      shadow: 'hover:shadow-[#FCCAE2]/40'
    },
    // Burgundy Theme
    { 
      bg: 'bg-[#5F2427]/10', 
      text: 'text-[#5F2427]', 
      border: 'hover:border-[#5F2427]', 
      icon: '#5F2427',
      shadow: 'hover:shadow-[#5F2427]/20'
    },
  ];

  const index = id.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0) % themes.length;
  return themes[index];
};

export const PageView: React.FC<PageViewProps> = ({
  node,
  childNodes,
  onNavigate,
  onCreateWhiteboard,
  onCreateFolder,
  onToggleFavorite,
  onUpdateNode,
  onReorderNode
}) => {
  const [searchQuery, setSearchQuery] = useState("");
  const [draggedItemId, setDraggedItemId] = useState<string | null>(null);

  // Renaming State (Grid Items)
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState("");

  // Renaming State (Header)
  const [isRenamingHeader, setIsRenamingHeader] = useState(false);
  const [headerName, setHeaderName] = useState("");

  const whiteboards = childNodes.filter(n => n.type === 'whiteboard');
  const folders = childNodes.filter(n => n.type !== 'whiteboard');

  const filteredWhiteboards = whiteboards.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));
  const filteredFolders = folders.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));

  // Don't show "Create" buttons in special views like Recents/Favorites unless appropriate
  const isSpecialView = ['recents', 'favorites'].includes(node.id);

  // --- Grid Renaming Handlers ---
  const handleStartRenaming = (e: React.MouseEvent, item: FileSystemNode) => {
    e.stopPropagation();
    e.preventDefault();
    setEditingId(item.id);
    setEditName(item.name);
  };

  const handleSaveRenaming = () => {
    if (editingId && editName.trim()) {
      onUpdateNode(editingId, { name: editName.trim() });
    }
    setEditingId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSaveRenaming();
    if (e.key === 'Escape') setEditingId(null);
  };

  // --- Header Renaming Handlers ---
  const handleStartHeaderRenaming = () => {
    if (isSpecialView) return;
    setIsRenamingHeader(true);
    setHeaderName(node.name);
  };

  const handleSaveHeaderRenaming = () => {
    if (headerName.trim()) {
      onUpdateNode(node.id, { name: headerName.trim() });
    }
    setIsRenamingHeader(false);
  };

  const handleHeaderKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSaveHeaderRenaming();
    if (e.key === 'Escape') setIsRenamingHeader(false);
  };

  // --- Drag and Drop Handlers ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      if (editingId || isRenamingHeader) {
          e.preventDefault();
          return;
      }
      setDraggedItemId(id);
      e.dataTransfer.setData('nodeId', id);
      e.dataTransfer.effectAllowed = 'move';
      if (e.target instanceof HTMLElement) {
          e.target.style.opacity = '0.5';
      }
  };

  const handleDragEnd = (e: React.DragEvent) => {
      setDraggedItemId(null);
      if (e.target instanceof HTMLElement) {
          e.target.style.opacity = '1';
      }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetId: string) => {
      e.preventDefault();
      const dragId = e.dataTransfer.getData('nodeId');
      if (dragId && dragId !== targetId && onReorderNode) {
          onReorderNode(dragId, targetId);
      }
      setDraggedItemId(null);
  };

  return (
    <div className="flex-1 bg-white h-full overflow-y-auto no-scrollbar font-sans selection:bg-[#FCCAE2] selection:text-[#5F2427]">
      <div className="max-w-[1400px] mx-auto p-8 lg:p-12">

        {/* --- HEADER --- */}
        <header className="flex flex-col gap-6 mb-10">

          {/* Top Row: Breadcrumbs / Title + Logo */}
          <div className="flex justify-between items-start">
             <div className="flex flex-col gap-2">
                 <div className="flex items-center gap-2 text-[13px] font-medium text-gray-400">
                    <span>Workspace</span>
                    <span className="text-[#FFD753]">/</span>
                    <span className="text-[#3A5C34]">{node.name}</span>
                 </div>

                 <div className="flex items-center gap-3 h-[48px]">
                    {node.icon && <span className="text-[32px]">{node.icon}</span>}

                    {isRenamingHeader ? (
                        <input
                            value={headerName}
                            onChange={(e) => setHeaderName(e.target.value)}
                            onBlur={handleSaveHeaderRenaming}
                            onKeyDown={handleHeaderKeyDown}
                            autoFocus
                            className="text-[32px] font-bold text-[#5F2427] tracking-tight leading-tight bg-transparent border-b-2 border-[#5F2427] outline-none w-full max-w-lg p-0 placeholder-[#5F2427]/30"
                        />
                    ) : (
                        // Using Deep Burgundy for the Header to give it weight and warmth
                        <h1 
                            className={`text-[32px] font-bold text-[#5F2427] tracking-tight leading-tight ${!isSpecialView ? 'cursor-text hover:text-[#3A5C34] transition-colors' : ''}`}
                            onDoubleClick={handleStartHeaderRenaming}
                        >
                            {node.name}
                        </h1>
                    )}
                 </div>
             </div>

             {/* Orbit Logo in Top Right Corner */}
             <OrbitLogo className="w-12 h-12 text-[#5F2427]" />
          </div>

          {/* Controls Row: Search & Actions */}
          <div className="flex items-center justify-between gap-4">
             {/* Search */}
             <div className="relative flex-1 max-w-sm group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3A5C34] transition-colors" size={16} />
                <input 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full h-10 bg-gray-50/50 border border-gray-200 rounded-xl pl-9 pr-4 text-[14px] text-gray-900 placeholder-gray-400 focus:ring-2 focus:ring-[#FCCAE2] focus:border-[#5F2427] transition-all outline-none"
                  placeholder="Filter items..."
                />
             </div>

             {/* Actions */}
             <div className="flex items-center gap-3">
                <div className="flex items-center bg-gray-50 p-0.5 rounded-xl border border-gray-200 mr-2">
                    <button className="p-1.5 bg-white rounded-lg shadow-sm text-[#3A5C34]"><Grid2X2 size={16}/></button>
                    <button className="p-1.5 text-gray-400 hover:text-[#5F2427]"><ListIcon size={16}/></button>
                </div>

                {!isSpecialView && (
                  <>
                    <button 
                      onClick={onCreateFolder}
                      className="h-9 px-4 rounded-xl bg-white border border-gray-200 text-[#3A5C34] font-medium text-[13px] hover:bg-gray-50 hover:border-[#3A5C34]/30 transition-all active:scale-95 flex items-center gap-2 shadow-sm"
                    >
                      <Folder size={14} className="text-[#FFD753] fill-[#FFD753]" />
                      New Folder
                    </button>

                    <button 
                      onClick={onCreateWhiteboard}
                      // New Chic Combo: Burgundy BG + Pink Text
                      className="h-9 px-4 rounded-xl bg-[#5F2427] text-[#FCCAE2] font-medium text-[13px] hover:bg-[#4a1c1e] transition-all active:scale-95 flex items-center gap-2 shadow-md shadow-[#5F2427]/20"
                    >
                      <Plus size={14} />
                      New Whiteboard
                    </button>
                  </>
                )}
             </div>
          </div>
        </header>

        {/* --- SECTIONS --- */}

        {/* 1. FOLDERS */}
        {(filteredFolders.length > 0 || (!searchQuery && !isSpecialView)) && (
            <section className="mb-12">
                <div className="flex items-center gap-2 mb-4">
                    <h2 className="text-[14px] font-semibold text-[#5F2427]">Folders</h2>
                    <span className="px-1.5 py-0.5 rounded-md bg-[#FCCAE2]/30 text-[11px] font-bold text-[#5F2427]">{filteredFolders.length}</span>
                </div>

                {filteredFolders.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                        {filteredFolders.map(folder => {
                            const theme = getBrandTheme(folder.id);
                            const isEditing = editingId === folder.id;

                            return (
                                <div 
                                    key={folder.id}
                                    onClick={() => !isEditing && onNavigate(folder.id)}
                                    draggable
                                    onDragStart={(e) => handleDragStart(e, folder.id)}
                                    onDragEnd={handleDragEnd}
                                    onDragOver={handleDragOver}
                                    onDrop={(e) => handleDrop(e, folder.id)}
                                    className={`
                                        group flex flex-col gap-3 p-4 rounded-2xl border bg-white transition-all text-left relative h-full cursor-pointer
                                        ${draggedItemId === folder.id 
                                            ? 'opacity-40 border-dashed border-[#3A5C34]' 
                                            : `border-gray-100 ${theme.border} hover:shadow-lg ${theme.shadow}`
                                        }
                                    `}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform ${folder.icon ? 'bg-gray-50' : theme.bg}`}>
                                            {folder.icon ? (
                                                <span className="text-[20px]">{folder.icon}</span>
                                            ) : (
                                                <Folder size={18} fill="currentColor" className={theme.text} />
                                            )}
                                        </div>
                                        <div className="min-w-0 flex-1">
                                            {isEditing ? (
                                                <input
                                                    value={editName}
                                                    onChange={(e) => setEditName(e.target.value)}
                                                    onBlur={handleSaveRenaming}
                                                    onKeyDown={handleKeyDown}
                                                    autoFocus
                                                    onClick={(e) => e.stopPropagation()}
                                                    className="w-full text-[14px] font-bold text-[#3A5C34] bg-white border border-[#3A5C34] rounded px-1 outline-none shadow-sm"
                                                />
                                            ) : (
                                                <h3 
                                                    className={`text-[14px] font-bold text-gray-900 truncate group-hover:${theme.text} transition-colors select-none`}
                                                    onDoubleClick={(e) => handleStartRenaming(e, folder)}
                                                >
                                                    {folder.name}
                                                </h3>
                                            )}
                                        </div>
                                    </div>

                                    {folder.description && (
                                        <p className="text-[12px] text-gray-500 leading-relaxed line-clamp-2 min-h-[32px]">
                                            {folder.description}
                                        </p>
                                    )}

                                    <div className="mt-auto pt-2 text-[11px] text-gray-400 font-medium flex items-center gap-1">
                                        <div className={`w-1.5 h-1.5 rounded-full ${theme.bg.replace('/20','').replace('/10','').replace('/40','')} opacity-50`}></div>
                                        {/* Mock count for visual completeness */}
                                        <span>0 items</span>
                                    </div>

                                    {onToggleFavorite && (
                                      <div 
                                        className="absolute top-2 right-2 p-1.5 rounded-full hover:bg-gray-100 text-gray-300 hover:text-[#FFD753] transition-all opacity-0 group-hover:opacity-100"
                                        onClick={(e) => { e.stopPropagation(); onToggleFavorite(folder.id); }}
                                      >
                                        <Star size={14} fill={folder.isFavorite ? "currentColor" : "none"} className={folder.isFavorite ? "text-[#FFD753]" : ""} />
                                      </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="text-gray-400 text-[13px] italic py-8 border border-dashed border-gray-200 rounded-2xl flex flex-col items-center justify-center bg-[#f9fafb]">
                        <Folder size={24} className="mb-2 opacity-20 text-[#3A5C34]" />
                        No folders found
                    </div>
                )}
            </section>
        )}

        {/* 2. WHITEBOARDS */}
        <section>
            <div className="flex items-center gap-2 mb-4">
                <h2 className="text-[14px] font-semibold text-[#5F2427]">Whiteboards</h2>
                <span className="px-1.5 py-0.5 rounded-md bg-[#FCCAE2]/30 text-[11px] font-bold text-[#5F2427]">{filteredWhiteboards.length}</span>
            </div>

            {filteredWhiteboards.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                    {/* Create New Card (Inline) - Only show if allowed */}
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            // Grid Button: Burgundy Border + Text on hover
                            className="group flex flex-col items-center justify-center gap-3 bg-white rounded-2xl border-2 border-dashed border-gray-200 hover:border-[#5F2427] hover:bg-[#FCCAE2]/10 transition-all cursor-pointer aspect-[4/3]"
                        >
                            <div className="w-12 h-12 rounded-full bg-white shadow-sm border border-gray-100 flex items-center justify-center text-gray-400 group-hover:text-[#5F2427] group-hover:scale-110 transition-all duration-300">
                                <Plus size={20} />
                            </div>
                            <span className="text-[13px] font-bold text-gray-400 group-hover:text-[#5F2427]">Create New</span>
                        </button>
                    )}

                    {filteredWhiteboards.map(wb => (
                        <div 
                          key={wb.id}
                          onClick={() => editingId !== wb.id && onNavigate(wb.id)}
                          draggable
                          onDragStart={(e) => handleDragStart(e, wb.id)}
                          onDragEnd={handleDragEnd}
                          onDragOver={handleDragOver}
                          onDrop={(e) => handleDrop(e, wb.id)}
                          className={`
                              group relative flex flex-col bg-white rounded-3xl border overflow-hidden transition-all duration-300 cursor-pointer
                              ${draggedItemId === wb.id 
                                  ? 'opacity-40 border-dashed border-[#3A5C34]' 
                                  : 'border-gray-100 hover:border-[#FCCAE2] hover:shadow-xl hover:shadow-[#5F2427]/5'
                              }
                          `}
                        >
                            {/* Preview Area - Light & Clean */}
                            <div className="aspect-[4/3] bg-[#f9fafb] relative overflow-hidden border-b border-gray-50">
                                {/* Dot Pattern Background */}
                                <div className="absolute inset-0 opacity-[0.3]" 
                                     style={{ backgroundImage: 'radial-gradient(#94a3b8 1px, transparent 1px)', backgroundSize: '16px 16px' }}>
                                </div>

                                {/* Abstract Content Hint (Using Brand Colors) */}
                                <div className="absolute inset-6 bg-white rounded-xl shadow-[0_4px_20px_-4px_rgba(0,0,0,0.1)] border border-gray-100 group-hover:scale-105 group-hover:-translate-y-1 transition-transform duration-500 flex flex-col p-3 gap-2">
                                    <div className="w-1/3 h-2 bg-gray-100 rounded-full"></div>
                                    <div className="flex gap-2">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/20 border border-[#3A5C34]/10"></div>
                                        <div className="w-8 h-8 rounded-lg bg-[#FCCAE2]/40 border border-[#FCCAE2]/20"></div>
                                        <div className="w-12 h-8 rounded-lg bg-[#FFD753]/20 border border-[#FFD753]/10 ml-auto"></div>
                                    </div>
                                    <div className="mt-auto w-1/2 h-2 bg-[#5F2427]/10 rounded-full"></div>
                                </div>

                                {/* Hover Overlay Button - Chic Burgundy & Yellow */}
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-white/40 backdrop-blur-[2px]">
                                    <div className="px-5 py-2 bg-[#5F2427] shadow-lg rounded-full text-[12px] font-bold text-[#FFD753] tracking-wide transform translate-y-2 group-hover:translate-y-0 transition-transform">
                                        Open Board
                                    </div>
                                </div>
                            </div>

                            {/* Info Footer */}
                            <div className="p-4 flex flex-col gap-1">
                                <div className="flex items-center justify-between gap-2">
                                    <div className="min-w-0 flex-1">
                                        {editingId === wb.id ? (
                                            <input
                                                value={editName}
                                                onChange={(e) => setEditName(e.target.value)}
                                                onBlur={handleSaveRenaming}
                                                onKeyDown={handleKeyDown}
                                                autoFocus
                                                onClick={(e) => e.stopPropagation()}
                                                className="w-full text-[14px] font-bold text-[#5F2427] bg-white border border-[#5F2427] rounded px-1 outline-none shadow-sm"
                                            />
                                        ) : (
                                            <h3 
                                                className="text-[14px] font-bold text-[#1C1C1E] truncate flex items-center gap-2 select-none group-hover:text-[#5F2427] transition-colors"
                                                onDoubleClick={(e) => handleStartRenaming(e, wb)}
                                            >
                                                {wb.icon && <span>{wb.icon}</span>}
                                                {wb.name}
                                            </h3>
                                        )}
                                    </div>

                                    {onToggleFavorite && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onToggleFavorite(wb.id); }}
                                            className={`hover:text-[#FFD753] transition-opacity shrink-0 ${wb.isFavorite ? 'text-[#FFD753] opacity-100' : 'text-gray-300 opacity-0 group-hover:opacity-100'}`}
                                        >
                                            <Star size={14} fill={wb.isFavorite ? "currentColor" : "none"} />
                                        </button>
                                    )}
                                </div>
                                <div className="flex items-center justify-between mt-1">
                                    <span className="text-[11px] text-gray-400 flex items-center gap-1 font-medium">
                                        <Clock size={10} /> {wb.lastEdited || 'Just now'}
                                    </span>
                                    <div className="flex -space-x-1.5">
                                        <div className="w-5 h-5 rounded-full bg-[#3A5C34] text-[#FFD753] border border-white flex items-center justify-center text-[8px] font-bold shadow-sm">JD</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center py-20 text-center border-2 border-dashed border-gray-200 rounded-3xl bg-[#f9fafb]">
                    <div className="w-16 h-16 bg-white rounded-2xl shadow-sm border border-gray-100 flex items-center justify-center mb-4">
                        <LayoutTemplate size={28} className="text-[#3A5C34] opacity-50" />
                    </div>
                    <p className="text-[15px] font-bold text-gray-900">No whiteboards created yet</p>
                    <p className="text-[13px] text-gray-500 mb-6 max-w-xs leading-relaxed">Start your first project in this folder to begin visualizing your strategy.</p>
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            // Empty State Button: Burgundy BG + Pink Text
                            className="px-6 py-2.5 rounded-full bg-[#5F2427] text-[#FCCAE2] font-semibold text-[13px] shadow-lg hover:bg-[#4a1c1e] transition-all hover:scale-105 active:scale-95"
                        >
                            Create Whiteboard
                        </button>
                    )}
                </div>
            )}
        </section>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { FileSystemNode } from '../types';
import { OrbitLogo } from './ui/OrbitLogo';
import { 
  Clock, 
  Star, 
  Plus, 
  Folder, 
  Search, 
  Grid2X2, 
  List as ListIcon, 
  LayoutTemplate,
  MoreHorizontal
} from 'lucide-react';

interface PageViewProps {
  node: FileSystemNode;
  childNodes: FileSystemNode[];
  onNavigate: (id: string) => void;
  onCreateWhiteboard: () => void;
  onCreateFolder: () => void;
  onToggleFavorite?: (id: string) => void;
  onUpdateNode: (id: string, updates: Partial<FileSystemNode>) => void;
  onReorderNode?: (dragId: string, targetId: string) => void;
}

// --- COLOR UTILS ---
// Deterministically assign a brand color theme based on the ID string
const getBrandTheme = (id: string) => {
  const themes = [
    // Yellow Theme
    { 
      bg: 'bg-[#FFD753]/20', 
      text: 'text-[#b89514]', 
      border: 'hover:border-[#FFD753]', 
      icon: '#d9b01c',
      shadow: 'hover:shadow-[#FFD753]/20'
    },
    // Green Theme
    { 
      bg: 'bg-[#3A5C34]/10', 
      text: 'text-[#3A5C34]', 
      border: 'hover:border-[#3A5C34]', 
      icon: '#3A5C34',
      shadow: 'hover:shadow-[#3A5C34]/20'
    },
    // Pink Theme
    { 
      bg: 'bg-[#FCCAE2]/40', 
      text: 'text-[#5F2427]', 
      border: 'hover:border-[#FCCAE2]', 
      icon: '#5F2427',
      shadow: 'hover:shadow-[#FCCAE2]/40'
    },
    // Burgundy Theme
    { 
      bg: 'bg-[#5F2427]/10', 
      text: 'text-[#5F2427]', 
      border: 'hover:border-[#5F2427]', 
      icon: '#5F2427',
      shadow: 'hover:shadow-[#5F2427]/20'
    },
  ];

  const index = id.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0) % themes.length;
  return themes[index];
};

export const PageView: React.FC<PageViewProps> = ({
  node,
  childNodes,
  onNavigate,
  onCreateWhiteboard,
  onCreateFolder,
  onToggleFavorite,
  onUpdateNode,
  onReorderNode
}) => {
  const [searchQuery, setSearchQuery] = useState("");
  const [draggedItemId, setDraggedItemId] = useState<string | null>(null);

  // Renaming State (Grid Items)
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState("");

  // Renaming State (Header)
  const [isRenamingHeader, setIsRenamingHeader] = useState(false);
  const [headerName, setHeaderName] = useState("");

  const whiteboards = childNodes.filter(n => n.type === 'whiteboard');
  const folders = childNodes.filter(n => n.type !== 'whiteboard');

  const filteredWhiteboards = whiteboards.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));
  const filteredFolders = folders.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));

  // Don't show "Create" buttons in special views like Recents/Favorites unless appropriate
  const isSpecialView = ['recents', 'favorites'].includes(node.id);

  // --- Grid Renaming Handlers ---
  const handleStartRenaming = (e: React.MouseEvent, item: FileSystemNode) => {
    e.stopPropagation();
    e.preventDefault();
    setEditingId(item.id);
    setEditName(item.name);
  };

  const handleSaveRenaming = () => {
    if (editingId && editName.trim()) {
      onUpdateNode(editingId, { name: editName.trim() });
    }
    setEditingId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSaveRenaming();
    if (e.key === 'Escape') setEditingId(null);
  };

  // --- Header Renaming Handlers ---
  const handleStartHeaderRenaming = () => {
    if (isSpecialView) return;
    setIsRenamingHeader(true);
    setHeaderName(node.name);
  };

  const handleSaveHeaderRenaming = () => {
    if (headerName.trim()) {
      onUpdateNode(node.id, { name: headerName.trim() });
    }
    setIsRenamingHeader(false);
  };

  const handleHeaderKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSaveHeaderRenaming();
    if (e.key === 'Escape') setIsRenamingHeader(false);
  };

  // --- Drag and Drop Handlers ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      if (editingId || isRenamingHeader) {
          e.preventDefault();
          return;
      }
      setDraggedItemId(id);
      e.dataTransfer.setData('nodeId', id);
      e.dataTransfer.effectAllowed = 'move';
      if (e.target instanceof HTMLElement) {
          e.target.style.opacity = '0.5';
      }
  };

  const handleDragEnd = (e: React.DragEvent) => {
      setDraggedItemId(null);
      if (e.target instanceof HTMLElement) {
          e.target.style.opacity = '1';
      }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetId: string) => {
      e.preventDefault();
      const dragId = e.dataTransfer.getData('nodeId');
      if (dragId && dragId !== targetId && onReorderNode) {
          onReorderNode(dragId, targetId);
      }
      setDraggedItemId(null);
  };

  return (
    <div className="flex-1 bg-white h-full overflow-y-auto no-scrollbar font-sans selection:bg-[#FCCAE2] selection:text-[#5F2427]">
      <div className="max-w-[1400px] mx-auto p-8 lg:p-12">

        {/* --- HEADER --- */}
        <header className="flex flex-col gap-6 mb-10">

          {/* Top Row: Breadcrumbs / Title + Logo */}
          <div className="flex justify-between items-end">
             <div className="flex flex-col gap-2">
                 <div className="flex items-center gap-2 text-[13px] font-medium text-gray-400">
                    <span>Workspace</span>
                    <span className="text-[#FFD753]">/</span>
                    <span className="text-[#3A5C34]">{node.name}</span>
                 </div>

                 <div className="flex items-center gap-3 h-[48px]">
                    {node.icon && <span className="text-[32px]">{node.icon}</span>}

                    {isRenamingHeader ? (
                        <input
                            value={headerName}
                            onChange={(e) => setHeaderName(e.target.value)}
                            onBlur={handleSaveHeaderRenaming}
                            onKeyDown={handleHeaderKeyDown}
                            autoFocus
                            className="text-[32px] font-bold text-[#5F2427] tracking-tight leading-tight bg-transparent border-b-2 border-[#5F2427] outline-none w-full max-w-lg p-0 placeholder-[#5F2427]/30"
                        />
                    ) : (
                        // Using Deep Burgundy for the Header to give it weight and warmth
                        <h1 
                            className={`text-[32px] font-bold text-[#5F2427] tracking-tight leading-tight ${!isSpecialView ? 'cursor-text hover:text-[#3A5C34] transition-colors' : ''}`}
                            onDoubleClick={handleStartHeaderRenaming}
                        >
                            {node.name}
                        </h1>
                    )}
                 </div>
             </div>

             {/* Orbit Logo in Top Right Corner - Resized to 40px and aligned to Title baseline */}
             <OrbitLogo className="w-10 h-10 text-[#5F2427] mb-1" />
          </div>

          {/* Controls Row: Search & Actions */}
          <div className="flex items-center justify-between gap-4">
             {/* Search */}
             <div className="relative flex-1 max-w-sm group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3A5C34] transition-colors" size={16} />
                <input 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full h-10 bg-gray-50/50 border border-gray-200 rounded-xl pl-9 pr-4 text-[14px] text-gray-900 placeholder-gray-400 focus:ring-2 focus:ring-[#FCCAE2] focus:border-[#5F2427] transition-all outline-none"
                  placeholder="Filter items..."
                />
             </div>

             {/* Actions */}
             <div className="flex items-center gap-3">
                <div className="flex items-center bg-gray-50 p-0.5 rounded-xl border border-gray-200 mr-2">
                    <button className="p-1.5 bg-white rounded-lg shadow-sm text-[#3A5C34]"><Grid2X2 size={16}/></button>
                    <button className="p-1.5 text-gray-400 hover:text-[#5F2427]"><ListIcon size={16}/></button>
                </div>

                {!isSpecialView && (
                  <>
                    <button 
                      onClick={onCreateFolder}
                      className="h-9 px-4 rounded-xl bg-white border border-gray-200 text-[#3A5C34] font-medium text-[13px] hover:bg-gray-50 hover:border-[#3A5C34]/30 transition-all active:scale-95 flex items-center gap-2 shadow-sm"
                    >
                      <Folder size={14} className="text-[#FFD753] fill-[#FFD753]" />
                      New Folder
                    </button>

                    <button 
                      onClick={onCreateWhiteboard}
                      // New Chic Combo: Burgundy BG + Pink Text
                      className="h-9 px-4 rounded-xl bg-[#5F2427] text-[#FCCAE2] font-medium text-[13px] hover:bg-[#4a1c1e] transition-all active:scale-95 flex items-center gap-2 shadow-md shadow-[#5F2427]/20"
                    >
                      <Plus size={14} />
                      New Whiteboard
                    </button>
                  </>
                )}
             </div>
          </div>
        </header>

        {/* --- SECTIONS --- */}

        {/* 1. FOLDERS */}
        {(filteredFolders.length > 0 || (!searchQuery && !isSpecialView)) && (
            <section className="mb-12">
                <div className="flex items-center gap-2 mb-4">
                    <h2 className="text-[14px] font-semibold text-[#5F2427]">Folders</h2>
                    <span className="px-1.5 py-0.5 rounded-md bg-[#FCCAE2]/30 text-[11px] font-bold text-[#5F2427]">{filteredFolders.length}</span>
                </div>

                {filteredFolders.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                        {filteredFolders.map(folder => {
                            const theme = getBrandTheme(folder.id);
                            const isEditing = editingId === folder.id;

                            return (
                                <div 
                                    key={folder.id}
                                    onClick={() => !isEditing && onNavigate(folder.id)}
                                    draggable
                                    onDragStart={(e) => handleDragStart(e, folder.id)}
                                    onDragEnd={handleDragEnd}
                                    onDragOver={handleDragOver}
                                    onDrop={(e) => handleDrop(e, folder.id)}
                                    className={`
                                        group flex flex-col gap-3 p-4 rounded-2xl border bg-white transition-all text-left relative h-full cursor-pointer
                                        ${draggedItemId === folder.id 
                                            ? 'opacity-40 border-dashed border-[#3A5C34]' 
                                            : `border-gray-100 ${theme.border} hover:shadow-lg ${theme.shadow}`
                                        }
                                    `}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform ${folder.icon ? 'bg-gray-50' : theme.bg}`}>
                                            {folder.icon ? (
                                                <span className="text-[20px]">{folder.icon}</span>
                                            ) : (
                                                <Folder size={18} fill="currentColor" className={theme.text} />
                                            )}
                                        </div>
                                        <div className="min-w-0 flex-1">
                                            {isEditing ? (
                                                <input
                                                    value={editName}
                                                    onChange={(e) => setEditName(e.target.value)}
                                                    onBlur={handleSaveRenaming}
                                                    onKeyDown={handleKeyDown}
                                                    autoFocus
                                                    onClick={(e) => e.stopPropagation()}
                                                    className="w-full text-[14px] font-bold text-[#3A5C34] bg-white border border-[#3A5C34] rounded px-1 outline-none shadow-sm"
                                                />
                                            ) : (
                                                <h3 
                                                    className={`text-[14px] font-bold text-gray-900 truncate group-hover:${theme.text} transition-colors select-none`}
                                                    onDoubleClick={(e) => handleStartRenaming(e, folder)}
                                                >
                                                    {folder.name}
                                                </h3>
                                            )}
                                        </div>
                                    </div>

                                    {folder.description && (
                                        <p className="text-[12px] text-gray-500 leading-relaxed line-clamp-2 min-h-[32px]">
                                            {folder.description}
                                        </p>
                                    )}

                                    <div className="mt-auto pt-2 text-[11px] text-gray-400 font-medium flex items-center gap-1">
                                        <div className={`w-1.5 h-1.5 rounded-full ${theme.bg.replace('/20','').replace('/10','').replace('/40','')} opacity-50`}></div>
                                        {/* Mock count for visual completeness */}
                                        <span>0 items</span>
                                    </div>

                                    {onToggleFavorite && (
                                      <div 
                                        className="absolute top-2 right-2 p-1.5 rounded-full hover:bg-gray-100 text-gray-300 hover:text-[#FFD753] transition-all opacity-0 group-hover:opacity-100"
                                        onClick={(e) => { e.stopPropagation(); onToggleFavorite(folder.id); }}
                                      >
                                        <Star size={14} fill={folder.isFavorite ? "currentColor" : "none"} className={folder.isFavorite ? "text-[#FFD753]" : ""} />
                                      </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="text-gray-400 text-[13px] italic py-8 border border-dashed border-gray-200 rounded-2xl flex flex-col items-center justify-center bg-[#f9fafb]">
                        <Folder size={24} className="mb-2 opacity-20 text-[#3A5C34]" />
                        No folders found
                    </div>
                )}
            </section>
        )}

        {/* 2. WHITEBOARDS */}
        <section>
            <div className="flex items-center gap-2 mb-4">
                <h2 className="text-[14px] font-semibold text-[#5F2427]">Whiteboards</h2>
                <span className="px-1.5 py-0.5 rounded-md bg-[#FCCAE2]/30 text-[11px] font-bold text-[#5F2427]">{filteredWhiteboards.length}</span>
            </div>

            {filteredWhiteboards.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                    {/* Create New Card (Inline) - Only show if allowed */}
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            // Grid Button: Burgundy Border + Text on hover
                            className="group flex flex-col items-center justify-center gap-3 bg-white rounded-2xl border-2 border-dashed border-gray-200 hover:border-[#5F2427] hover:bg-[#FCCAE2]/10 transition-all cursor-pointer aspect-[4/3]"
                        >
                            <div className="w-12 h-12 rounded-full bg-white shadow-sm border border-gray-100 flex items-center justify-center text-gray-400 group-hover:text-[#5F2427] group-hover:scale-110 transition-all duration-300">
                                <Plus size={20} />
                            </div>
                            <span className="text-[13px] font-bold text-gray-400 group-hover:text-[#5F2427]">Create New</span>
                        </button>
                    )}

                    {filteredWhiteboards.map(wb => (
                        <div 
                          key={wb.id}
                          onClick={() => editingId !== wb.id && onNavigate(wb.id)}
                          draggable
                          onDragStart={(e) => handleDragStart(e, wb.id)}
                          onDragEnd={handleDragEnd}
                          onDragOver={handleDragOver}
                          onDrop={(e) => handleDrop(e, wb.id)}
                          className={`
                              group relative flex flex-col bg-white rounded-3xl border overflow-hidden transition-all duration-300 cursor-pointer
                              ${draggedItemId === wb.id 
                                  ? 'opacity-40 border-dashed border-[#3A5C34]' 
                                  : 'border-gray-100 hover:border-[#FCCAE2] hover:shadow-xl hover:shadow-[#5F2427]/5'
                              }
                          `}
                        >
                            {/* Preview Area - Light & Clean */}
                            <div className="aspect-[4/3] bg-[#f9fafb] relative overflow-hidden border-b border-gray-50">
                                {/* Dot Pattern Background */}
                                <div className="absolute inset-0 opacity-[0.3]" 
                                     style={{ backgroundImage: 'radial-gradient(#94a3b8 1px, transparent 1px)', backgroundSize: '16px 16px' }}>
                                </div>

                                {/* Abstract Content Hint (Using Brand Colors) */}
                                <div className="absolute inset-6 bg-white rounded-xl shadow-[0_4px_20px_-4px_rgba(0,0,0,0.1)] border border-gray-100 group-hover:scale-105 group-hover:-translate-y-1 transition-transform duration-500 flex flex-col p-3 gap-2">
                                    <div className="w-1/3 h-2 bg-gray-100 rounded-full"></div>
                                    <div className="flex gap-2">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/20 border border-[#3A5C34]/10"></div>
                                        <div className="w-8 h-8 rounded-lg bg-[#FCCAE2]/40 border border-[#FCCAE2]/20"></div>
                                        <div className="w-12 h-8 rounded-lg bg-[#FFD753]/20 border border-[#FFD753]/10 ml-auto"></div>
                                    </div>
                                    <div className="mt-auto w-1/2 h-2 bg-[#5F2427]/10 rounded-full"></div>
                                </div>

                                {/* Hover Overlay Button - Chic Burgundy & Yellow */}
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-white/40 backdrop-blur-[2px]">
                                    <div className="px-5 py-2 bg-[#5F2427] shadow-lg rounded-full text-[12px] font-bold text-[#FFD753] tracking-wide transform translate-y-2 group-hover:translate-y-0 transition-transform">
                                        Open Board
                                    </div>
                                </div>
                            </div>

                            {/* Info Footer */}
                            <div className="p-4 flex flex-col gap-1">
                                <div className="flex items-center justify-between gap-2">
                                    <div className="min-w-0 flex-1">
                                        {editingId === wb.id ? (
                                            <input
                                                value={editName}
                                                onChange={(e) => setEditName(e.target.value)}
                                                onBlur={handleSaveRenaming}
                                                onKeyDown={handleHeaderKeyDown}
                                                autoFocus
                                                onClick={(e) => e.stopPropagation()}
                                                className="w-full text-[14px] font-bold text-[#5F2427] bg-white border border-[#5F2427] rounded px-1 outline-none shadow-sm"
                                            />
                                        ) : (
                                            <h3 
                                                className="text-[14px] font-bold text-[#1C1C1E] truncate flex items-center gap-2 select-none group-hover:text-[#5F2427] transition-colors"
                                                onDoubleClick={(e) => handleStartRenaming(e, wb)}
                                            >
                                                {wb.icon && <span>{wb.icon}</span>}
                                                {wb.name}
                                            </h3>
                                        )}
                                    </div>

                                    {onToggleFavorite && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onToggleFavorite(wb.id); }}
                                            className={`hover:text-[#FFD753] transition-opacity shrink-0 ${wb.isFavorite ? 'text-[#FFD753] opacity-100' : 'text-gray-300 opacity-0 group-hover:opacity-100'}`}
                                        >
                                            <Star size={14} fill={wb.isFavorite ? "currentColor" : "none"} />
                                        </button>
                                    )}
                                </div>
                                <div className="flex items-center justify-between mt-1">
                                    <span className="text-[11px] text-gray-400 flex items-center gap-1 font-medium">
                                        <Clock size={10} /> {wb.lastEdited || 'Just now'}
                                    </span>
                                    <div className="flex -space-x-1.5">
                                        <div className="w-5 h-5 rounded-full bg-[#3A5C34] text-[#FFD753] border border-white flex items-center justify-center text-[8px] font-bold shadow-sm">JD</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center py-20 text-center border-2 border-dashed border-gray-200 rounded-3xl bg-[#f9fafb]">
                    <div className="w-16 h-16 bg-white rounded-2xl shadow-sm border border-gray-100 flex items-center justify-center mb-4">
                        <LayoutTemplate size={28} className="text-[#3A5C34] opacity-50" />
                    </div>
                    <p className="text-[15px] font-bold text-gray-900">No whiteboards created yet</p>
                    <p className="text-[13px] text-gray-500 mb-6 max-w-xs leading-relaxed">Start your first project in this folder to begin visualizing your strategy.</p>
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            // Empty State Button: Burgundy BG + Pink Text
                            className="px-6 py-2.5 rounded-full bg-[#5F2427] text-[#FCCAE2] font-semibold text-[13px] shadow-lg hover:bg-[#4a1c1e] transition-all hover:scale-105 active:scale-95"
                        >
                            Create Whiteboard
                        </button>
                    )}
                </div>
            )}
        </section>

      </div>
    </div>
  );
};

