            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3A5C34] transition-colors" />
            <input 
              className="w-full bg-white border border-gray-200 rounded-lg pl-8 pr-3 py-1.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 focus:border-[#3A5C34] outline-none transition-all placeholder-gray-400"
              placeholder="Search..."
              value={searchTerm}
