    green:  { 
        bg: 'bg-[#3A5C34]/5', 
        border: 'border-[#3A5C34]/10', 
        title: 'text-[#3A5C34]', 
        text: 'text-[#1C1C1E]', 
        placeholder: 'placeholder-[#3A5C34]/40', 
        checkbox: 'border-[#3A5C34]/30 text-[#3A5C34]', 
        checkboxActive: 'bg-[#3A5C34] border-[#3A5C34] text-white', 
