                                        <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-600 flex items-center justify-center"><Smartphone size={16}/></div>
                                        <span className="text-[12px] font-medium text-gray-600 group-hover:text-gray-900">Device Frames</span>
                                    </button>
                                    <button onClick={() => addCard(CardType.REMOVE_BG, "BG Remover")} className="flex items-center gap-3 p-2 rounded-xl hover:bg-gray-100 transition-colors group">
                                        <div className="w-8 h-8 rounded-lg bg-pink-100 text-pink-600 flex items-center justify-center"><Eraser size={16}/></div>
                                        <span className="text-[12px] font-medium text-gray-600 group-hover:text-gray-900">BG Remover</span>
