                            {/* Section 4: Strategy & Ops (Miro Bridge) */}
                            <div>
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Strategy & Ops</h3>
                                <div className="grid grid-cols-2 gap-2">
                                    <button onClick={() => addCard(CardType.SMART_CONNECTOR, "Smart Connector")} className="flex items-center gap-3 p-2 rounded-xl hover:bg-gray-100 transition-colors group">
                                        <div className="w-8 h-8 rounded-lg bg-indigo-100 text-indigo-600 flex items-center justify-center"><GitMerge size={16}/></div>
                                        <span className="text-[12px] font-medium text-gray-600 group-hover:text-gray-900">Connectors</span>
                                    </button>
                                    <button onClick={() => addCard(CardType.APPROVAL_STAMP, "Approval Stamp")} className="flex items-center gap-3 p-2 rounded-xl hover:bg-gray-100 transition-colors group">
                                        <div className="w-8 h-8 rounded-lg bg-green-100 text-green-600 flex items-center justify-center"><Stamp size={16}/></div>
                                        <span className="text-[12px] font-medium text-gray-600 group-hover:text-gray-900">Voting / Stamp</span>
                                    </button>
                                    <button onClick={() => addCard(CardType.JOURNEY_MAP, "Journey Map")} className="flex items-center gap-3 p-2 rounded-xl hover:bg-gray-100 transition-colors group">
                                        <div className="w-8 h-8 rounded-lg bg-yellow-100 text-yellow-600 flex items-center justify-center"><Map size={16}/></div>
