                        {/* Redo */}
                        <button 
                            onClick={handleRedo} 
                            disabled={future.length === 0} 
                            className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/5 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        >
