                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
