const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427'; // Default Burgundy
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color }; // Yellow -> Dark Gold Text
        case '#FCCAE2': return { text: '#9D174D', bg: color }; // Pink -> Dark Pink Text
        case '#FF9500': return { text: '#C2410C', bg: color }; // Orange -> Dark Orange Text
        default: return { text: color, bg: color };
    }
};

type ToolCategory = 'ESSENTIALS' | 'SOCIAL' | 'PAID' | 'PRODUCTION' | 'STRATEGY';

