                                            onClick={() => !isEditing && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => startTabRename(e, ws)}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`
                                                px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] outline-none cursor-pointer
                                                ${isActive ? 'font-bold' : 'font-medium text-gray-500'}
                                            `}
                                            style={{
                                                color: (isActive || isHovered) ? textColor : undefined,
                                                backgroundColor: (isActive || isHovered) ? `${activeColor}${bgOpacity}` : 'transparent'
                                            }}
                                        >
                                            {isEditing ? (
                                                <input 
                                                    autoFocus
                                                    value={editTabName}
                                                    onChange={(e) => setEditTabName(e.target.value)}
                                                    onBlur={finishTabRename}
                                                    onKeyDown={handleTabKeyDown}
                                                    className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit focus:ring-0 focus:border-none"
                                                    onClick={(e) => e.stopPropagation()}
                                                />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}

                                            {isActive && !isEditing && (
                                                <div 
                                                    onClick={(e) => toggleColorPicker(e, ws.id)} 
                                                    className="p-0.5 rounded hover:bg-black/5 cursor-pointer transition-colors ml-1"
                                                >
                                                    <ChevronDown size={10} strokeWidth={3} />
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
